    <title> Thời Đại Tam Quốc - Trình Tạo Kịch Bản</title>
    <style>
        #app.sango-wrapper {
            --bg-primary: #181a1b;
            --bg-card: #222526;
            --bg-card-hover: #2c3031;
            --bg-input: #1e2122;
            --text-primary: #d6d9d4;
            --text-secondary: #9fa6a2;
            --text-muted: #737a76;
            --theme-main: #6b8e88;
