            border-radius: 8px;
            box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
        }

        #app.sango-wrapper *,
        #app.sango-wrapper *::before,
        #app.sango-wrapper *::after {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
