            letter-spacing: 0.05em;
        }

        #app.sango-wrapper .input-group {
            display: flex;
            flex-direction: column;
            gap: var(--space-md);
            width: 100%;
            max-width: 400px;
        }

        #app.sango-wrapper .input-field,
        #app.sango-wrapper .textarea-field {
            width: 100%;
            padding: var(--space-sm) var(--space-md);
            background: var(--bg-input);
            border: 1px solid var(--border);
            border-radius: 4px;
            color: var(--text-primary);
            font-size: var(--fs-lg);
            font-family: inherit;
            outline: none;
            transition: all 0.3s;
        }

        #app.sango-wrapper .input-field {
            text-align: center;
            letter-spacing: 0.1em;
        }

        #app.sango-wrapper .textarea-field {
            letter-spacing: 0.05em;
            line-height: 1.8;
            resize: vertical;
            min-height: 80px;
        }

        #app.sango-wrapper .input-field:focus,
        #app.sango-wrapper .textarea-field:focus {
            border-color: var(--theme-main);
            box-shadow: var(--shadow-theme);
        }

        #app.sango-wrapper .card-grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
            gap: var(--space-md);
            width: 100%;
        }

        #app.sango-wrapper .sub-grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
