        #app.sango-wrapper .card.disabled,
        #app.sango-wrapper .sub-card.disabled {
            cursor: not-allowed;
            opacity: 0.5;
        }

        #app.sango-wrapper .card.disabled:hover,
        #app.sango-wrapper .sub-card.disabled:hover {
