<body>

    <div class="sango-wrapper" id="app">
        <!-- PAGE 0: Trang Bìa -->
        <div class="page active" id="page-0">
            <div class="page-inner">
                <h1 class="page-title" style="font-size:var(--fs-3xl);"> Thời Đại Tam Quốc</h1>
                <p class="page-guide"> Hán thất suy đồi, quần hùng nổi dậy. Cửu châu chấn động, can qua không dứt.<br> Đây là loạn thế của bạn, bánh xe vận mệnh đang chờ chuyển động.</p>
                <div class="btn-row" style="margin-top:var(--space-lg);"><button class="btn" id="start-button"> Bước vào phân tranh</button></div>
            </div>
        </div>

        <!-- PAGE 1: Chọn tuyến đường và tên thật -->
        <div class="page" id="page-1">
            <div class="page-inner">
                <h2 class="page-title"> Kịch bản và tên thật</h2>
                <p class="page-guide"> Chọn thế đạo của bạn, khắc ghi tên thật của bạn.</p>
                <div id="route-choice-cards" class="card-grid"></div>
                <div id="mode-choice-cards" class="card-grid" style="display:none; margin-top: 16px;"></div>
                <div id="direction-choice-cards" class="card-grid" style="display:none; margin-top: 16px;"></div>

                <div id="origin-details-custom" class="details-container">
                    <p class="page-guide" style="margin-bottom: 0;"> Lưu danh sử xanh, hay chìm vào cát bụi, đều bắt đầu từ hôm nay.</p>
                    <div class="input-group">
                        <input class="input-field" id="input-name" type="text" placeholder="Nhập họ tên" maxlength="1000">
                        <input class="input-field" id="input-zi" type="text" placeholder="Nhập biểu tự (Tùy chọn)" maxlength="1000">
                        <input class="input-field" id="input-age" type="number" placeholder="Nhập tuổi">
                    </div>
                </div>
                <div class="btn-row">
                    <button class="btn btn-back" onclick="goToPage(0)"> Quay lại</button>
                    <button class="btn" onclick="saveOrigin()"> Tiếp theo</button>
                </div>
            </div>
        </div>

        <!-- PAGE Lord-1: Chọn chủ công -->
        <div class="page" id="page-lord-1">
            <div class="page-inner">
                <h2 class="page-title"> Chọn chủ công</h2>
                <p class="page-guide"> Hóa thân quần hùng, thống lĩnh thiên quân vạn mã tranh bá thiên hạ.</p>
                <div id="lord-cards" class="card-grid"></div>
                <div class="btn-row">
                    <button class="btn btn-back" onclick="goToPage(1)"> Quay lại</button>
                    <button class="btn" onclick="saveLord()"> Tiếp theo</button>
                </div>
            </div>
        </div>

        <!-- PAGE Lord-2: Chọn kịch bản chủ công -->
        <div class="page" id="page-lord-2">
            <div class="page-inner">
                <h2 class="page-title"> Đại Thế Thời Đại</h2>
                <p class="page-guide" id="lord-situation-guide"> Chọn mốc thời gian bạn giáng lâm.</p>
                <div id="lord-situation-cards" class="card-grid" style="grid-template-columns: 1fr;"></div>
                <div class="btn-row">
                    <button class="btn btn-back" onclick="goToPage('lord-1')"> Quay lại</button>
                    <button class="btn" onclick="saveLordSituation()"> Tiếp theo</button>
                </div>
            </div>
        </div>

        <!-- PAGE 2: Đại Thế Thời Đại (Tuyến đường tự tạo) -->
        <div class="page" id="page-2">
            <div class="page-inner">
                <h2 class="page-title"> Đại Thế Thời Đại</h2>
                <p class="page-guide" id="situation-guide"> Đại thế phân hợp, bạn sẽ giáng lâm vào mốc thời gian nào?</p>
                <div id="situation-cards" class="card-grid" style="grid-template-columns: 1fr;"></div>
                <div class="btn-row">
                    <button class="btn btn-back" onclick="goToPage(1)"> Quay lại</button>
                    <button class="btn" onclick="saveSituation()"> Tiếp theo</button>
                </div>
            </div>
        </div>

        <!-- PAGE 3: Phe phái trực thuộc -->
        <div class="page" id="page-3">
            <div class="page-inner">
                <h2 class="page-title"> Phe phái trực thuộc</h2>
                <p class="page-guide"> Thiên hạ đại loạn, quần hùng cát cứ. Bạn chọn cống hiến cho ai, hay tự lập môn hộ?</p>
                <div id="faction-cards" class="card-grid"></div>
                <div id="custom-faction-container" class="input-group" style="display:none; margin-top: var(--space-lg); width:100%; max-width: 400px;">
                    <input class="input-field" id="input-custom-faction" type="text" placeholder="Nhập tên phe phái tùy chỉnh">
                </div>
                <div class="btn-row">
                    <button class="btn btn-back" onclick="goToPage(2)"> Quay lại</button>
                    <button class="btn" onclick="saveFaction()"> Tiếp theo</button>
                </div>
            </div>
        </div>

        <!-- PAGE 4: Thân phận và giai cấp / Nắm giữ thế lực -->
        <div class="page" id="page-4">
            <div class="page-inner">
                <h2 class="page-title" id="page-4-title"> Thân phận và giai cấp</h2>
                <p class="page-guide" id="page-4-guide"> Vương hầu tướng tướng, há cứ phải con dòng cháu giống? Hãy xác định xuất thân môn đệ trước, rồi mới định quan chức cao thấp.</p>

                <!-- Ô nhập liệu chế độ Diễn nghĩa -->
                <div id="romance-position-container" style="display:none; width: 100%; flex-direction: column; align-items: center;">
                    <div class="input-group" style="margin-top: var(--space-lg); width:100%; max-width: 400px;">
