                        'Đông Ngô trận doanh': ['Chu Du giả đồ diệt Quắc kế bị nhìn thấu, tức đến kim sang tịnh liệt trụy mã, ngươi ở trước trận hộ vệ chủ soái đột phá vòng vây..'],
                        'Tào Tháo quân': ['Xích Bích chiến bại lui về phương bắc, trên đường tao ngộ dịch bệnh, ngươi phụ trách phần thiêu từng đống đồng bào thi thể..']
                    },
                    211: {
                        'Lưu Bị quân': ['Ngươi theo quân nhập Thục, tiếp tế tuyến kéo dài ba ngàn dặm, kho lương Gia Manh Quan bị một trận mạc danh đại hỏa thiêu hủy một nửa..'],
                        'Tây Lương quân': ['Mã Siêu Hàn Toại trúng ly gián kế chém giết lẫn nhau, Tây Lương đại quân trước băng thành phân băng ly tích..'],
                        'Tào Tháo quân': ['Mã Siêu giết đến Tào Tháo cắt râu vứt áo, ngươi trong loạn quân bị Tây Lương thiết kỵ giẫm gãy hai chân..'],
                        'Ích Châu Lưu Chương': ['Đón Lưu Bị nhập Thục dẫn sói vào nhà, ngươi ở tiền tuyến bị Lưu Bị quân bao vây, trong thành đã không còn lương thảo..']
                    },
                    214: {
                        'Lưu Bị quân': ['Trương Phi nghĩa thích Nghiêm Nhan, nhưng đánh Thành Đô vẫn tao ngộ tử trung ngoan kháng, ngươi bị phái đi làm tử sĩ tiên đăng..', 'Bàng Thống chết ở Lạc Phượng Pha, ngươi bị kẹt trong sơn cốc chật hẹp, đường lui bị cự thạch tiệt đoạn, đầy trời tiễn vũ trút xuống..'],
                        'Ích Châu quân': ['Lưu Chương khai thành đầu hàng, thân là chủ chiến phái ngươi bị tước đoạt binh quyền sung làm phu lỗ..'],
                        'Đông Ngô trận doanh': ['Lữ Mông công thủ Kinh Châu ba quận, Quan Vũ suất đại quân phản công, ngươi ở dưới thành Trường Sa đối mặt thủy quân..'],
                        'Ích Châu Lưu Chương': ['Lưu Bị đại quân bức cận Thành Đô, các quận huyện vọng phong nhi hàng, thủ tướng đã chuẩn bị giết ngươi hiến thành..'],
                        'Tào Tháo quân': ['Tuân Úc vì phản đối xưng Ngụy công bị ép tự sát, trong quân nhân tâm hoảng sợ, ngươi vì lời nói đắc tội bị truy nã..', 'Tây chinh Hán Trung tao ngộ hiểm trở, sơn đạo gập ghềnh lương thảo không đủ, đại quân hãm vào tiến thoái lưỡng nan tử địa..'],
                        'Tào Ngụy quân': ['Tây chinh Trương Lỗ đại quân tao ngộ đoạn lương, tướng sĩ vì mệt mỏi đã có khuynh hướng đảo qua..'],
                        'Thục Hán trận doanh': ['Mã Siêu đầu bôn Lưu Bị dẫn tới nội bộ tướng lĩnh không phục, ngươi trong doanh bắt buộc cẩn thận đứng đội..'],
                        'Hán Trung thủ quân': ['Trú thủ Dương Bình Quan ngươi phát hiện mưu sĩ đã nhận hối lộ, chuẩn bị ban đêm khai thành hiến hàng..']
                    },
                    215: {
                        'Đông Ngô trận doanh': ['Trương Liêu tám trăm phá mười vạn, chiến hữu bên cạnh ngươi bị chém thành nhục nê, Tôn Quyền ở Tiêu Dao Tân túng mã dược kiều suýt nữa bị bắt..'],
                        'Tào Ngụy thủ quân': ['Mười vạn Ngô quân vây công Hợp Phì, trong thành mưa to như trút bùng phát ôn dịch, ngươi ngay cả khí lực giơ lên trường mâu cũng không còn..'],
                        'Thục Hán trận doanh': ['Quan Vũ đơn đao phó hội Đông Ngô đại doanh, ngươi thân là tùy hành thân vệ lòng bàn tay toàn là mồ hôi, bốn phía bố mãn đao phủ thủ..'],
                        'Thục Hán Kinh Châu quân': ['Quan Vũ phó yến, ngươi lái tiểu chu ở giữa sông tiếp ứng, Đông Ngô lâu thuyền đã ẩn ẩn thành thế bao vây..'],
                        'Đông Ngô thủy quân': ['Lỗ Túc bị Quan Vũ đơn đao hiệp trì, ngươi ném chuột sợ vỡ đồ không dám phóng tiễn, trơ mắt nhìn hắn thối lui..']
                    },
                    219: {
                        'Thục Hán quân': ['Quan Vũ bại tẩu Mạch Thành bị bắt, ngươi đối mặt bốn phương tám hướng Đông Ngô trường thương, đột phá vòng vây vô vọng..', 'Mãnh công Hán Trung tao ngộ Hạ Hầu Uyên tử thủ, ngươi ở dưới Định Quân Sơn bị Tào quân gỗ lăn đập gãy cánh tay..'],
                        'Tào Ngụy quân': ['Thủy yêm thất quân, ngươi bị vây trên tường thành ngâm nước, sát mã sung đói, cứu viện xa vời vô kỳ..', 'Hạ Hầu Uyên bị Hoàng Trung trận trảm, Tào quân toàn tuyến băng hội, Bạch Nhĩ Binh của Triệu Vân đang từ hậu phương thu gặt..'],
                        'Đông Ngô quân': ['Vừa chiếm lĩnh Kinh Châu lập túc chưa vững, trong thành Quan Vũ tàn bộ liều chết phản công hạng chiến, ngươi trong đống người chết giả chết..'],
                        'Thục Hán tàn quân': ['Giang Lăng thất hãm gia quyến bị bắt, ngươi mang theo mười mấy tàn binh trong rừng cây né tránh Đông Ngô chó săn..'],
                        'Đông Ngô trận doanh': ['Nhu Tu Khẩu lại lần nữa cùng Tào quân giao chiến, ngươi trên mặt sông tao ngộ Tào quân liên nỗ phúc cái xạ kích..']
                    },
                    221: {
                        'Thục Hán quân': ['Trương Phi bị bộ tướng ám sát, Lưu Bị cố chấp phạt Ngô, ngươi bị ép trong khốc thử hướng nguyên thủy sâm lâm tiến quân..'],
                        'Đông Ngô quân': ['Thục Hán đại quân thuận giang nhi hạ thế như chẻ tre, ngươi ở Tỷ Quy tiền tuyến bị Thục quân bao vây đoạn tuyệt đường lui..'],
                        'Tào Ngụy trận doanh': ['Tào Phi suy hành Cửu Phẩm Trung Chính chế, ngươi xuất thân hàn môn, vừa lập chiến công liền bị thế gia tử đệ tước đoạt quân chức..']
