                        'Đông Ngô quân': ['Truy kích bại quân lúc lầm nhập Bát Trận Đồ, phi sa tẩu thạch, mấy vạn Ngô quân lạc lối trong loạn thạch..'],
                        'Tào Ngụy trận doanh': ['Ba lộ phạt Ngô vô công nhi phản đại dịch lưu hành, doanh trướng ngươi ở trong một ngày bệnh chết một nửa người..']
                    },
                    223: {
                        'Thục Hán triều đình': ['Lưu Bị Bạch Đế Thành bệnh thệ thác cô, triều dã chấn động, Nam Trung hào cường thừa cơ tác loạn, Thục Hán đối mặt phúc diệt nguy cơ..'],
                        'Đông Ngô trận doanh': ['Nghe đồn Lưu Bị thác cô Gia Cát Lượng, ngươi bị phái đi thăm dò Thục Ngô có thể hay không nối lại tình xưa, tùy thời có thể bị giam giữ trảm thủ..'],
                        'Tào Ngụy trận doanh': ['Thừa dịp Lưu Bị tân tang, Tư Mã Ý hiến kế năm lộ phạt Thục, ngươi thân là tiên phong đang xuyên qua hiểm ác Tần Lĩnh sạn đạo..']
                    },
                    225: {
