                    249: {
                        'Tư Mã thị trận doanh': ['Tham dự chính biến một khi thất bại tức mãn môn sao trảm, ngươi ở cổng thành Lạc Dương nắm chặt trường mâu run rẩy..'],
                        'Tào Sảng dư đảng': ['Tư Mã Ý chỉ Lạc Thủy vi thệ sau nháy mắt trở mặt, đề kỵ đang tông cửa nhà ngươi chuẩn bị diệt tộc..'],
                        'Thục Hán quân': ['Khương Duy xuất binh Lũng Hữu ý đồ hô ứng Trung Nguyên, lại ở Khúc Sơn bị Quách Hoài đại quân cắt đứt đường về..']
                    },
                    251: {
