                    263: {
                        'Tào Ngụy phạt Thục quân': ['Đặng Ngải thâu độ Âm Bình, bảy trăm dặm không người ở, sĩ binh cực độ cơ ngạ gặm nuốt huyết nhục người chết..'],
                        'Thục Hán phòng ngự quân': ['Gia Cát Chiêm chiến tử Miên Trúc, Đặng Ngải binh lâm Thành Đô, hậu chủ tự phược xuất hàng, ngươi rút ra bội kiếm chuẩn bị tự vẫn..'],
                        'Đông Ngô viện quân': ['Cứu viện Thục Hán chậm một bước, ngươi ở Ba Đông tao ngộ Tấn quân phục kích tiến thoái thất cứ..']
                    },
                    264: {
                        'Tào Ngụy quân': ['Chung Hội Đặng Ngải tranh công bùng phát binh biến, ngươi ở Thành Đô tao ngộ loạn dân và phiến quân song trọng giáp kích..'],
                        'Chung Hội phán quân': ['Mật mưu cứ Thục tự lập bại lộ, tướng lĩnh xôn xao, ngươi thân là thân tín bị loạn binh chặn trong đại trướng loạn nhận phân thây..'],
                        'Thục Hán tàn quân': ['Khương Duy trá hàng kế bại tự vẫn, ngươi thân là cựu thần trong loạn quân yểm hộ gia quyến tuyệt vọng đào vong..'],
                        'Tây Tấn triều đình': ['Tư Mã Chiêu thiết yến thăm dò Lưu Thiện, ngươi thân là bồi khách nếu lộ ra vẻ đồng tình liền có sát thân chi họa..'],
                        'Thục Hán vong thần': ['Hậu chủ cười đáp "Lạc bất tư Thục", ngươi quỳ giữa tiệc gào khóc thảm thiết, bị Tấn quân giáp sĩ kéo ra khỏi đại điện..'],
                        'Tào Ngụy trận doanh': ['Thục Hán bình định sau tướng sĩ trệ lưu thủy thổ bất phục, ngươi nhiễm phải ác tật liên nhật sốt cao không lùi..'],
                        'Đông Ngô trận doanh': ['Tôn Hạo sơ thời minh đoán sau cực độ tàn bạo, ngươi vì khuyên can bị hạ lệnh khoét đi hai mắt..']
                    },
                    272: {
                        'Tây Tấn quân': ['Dương Hỗ tiến quân Tây Lăng tao ngộ Lục Kháng trở kích, ngươi ở bên Trường Giang bị hỏa thuyền thiêu đứt phù kiều..'],
                        'Đông Ngô quân': ['Bộ Xiển phán hàng Tây Tấn, Lục Kháng tử thủ Tây Lăng, ngươi trên tường thành tao ngộ Tấn quân hai mặt giáp kích..']
                    },
                    279: {
                        'Tây Tấn phạt Ngô quân': ['Mặt sông trải rộng thiết trùy ám tiêu, khoang đáy chiến thuyền của ngươi bị đâm thủng nước sông điên cuồng tràn vào..'],
                        'Đông Ngô phòng ngự quân': ['Tấn quân lâu thuyền thuận giang nhi hạ, Kiến Nghiệp phòng tuyến toàn tuyến băng hội, Tôn Hạo xuất hàng..']
                    },
                    280: {
                        'Tây Tấn triều đình': ['Thiên hạ nhất thống đại phong công thần, ngươi thân là để tằng quân quan vô thưởng còn bị cưỡng ép tài triệt khiển phản..'],
                        'Tại dã/Ẩn sĩ': ['Thế gia môn phiệt lũng đoạn giai tầng, ngươi luống có tài hoa lại chỉ có thể ẩn cư sơn lâm đốn củi sống qua ngày..']
                    }
                },
                'Chính Sử': {
                    159: {
                        'Đông Hán triều đình': ['Bọn hoạn quan Đơn Siêu mượn lệnh Hoàn Đế đột kích đại tướng quân phủ, ngươi thân là cung thành vệ sĩ bị cuốn vào huyết tinh hỗn chiến..'],
                        'Ngoại thích thế lực': ['Lương Ký binh bại ẩm dược tự sát, đình úy đang theo danh sách từng nhà truy nã Lương thị môn sinh, đề kỵ đã đập vỡ đại môn của ngươi..'],
                        'Hoạn quan thế lực': ['Ngươi thay Ngũ Hầu tịch thu Lương thị gia sản lúc tư thôn ngọc khí, ám thám của Đông Xưởng đã đem chủy thủ chống đỡ sau eo ngươi..'],
                        'Sĩ tộc thanh lưu': ['Ngươi dâng thư thống xích hoạn quan bả trì triều chính, hoàng môn lệnh suốt đêm ngụy tạo mưu phản tín kiện của ngươi trình đệ ngự án..'],
                        'Địa phương châu quận': ['Triều dã rung chuyển dẫn tới địa phương hào cường kiêm tịnh gia kịch, huyện thành của ngươi bị mấy trăm trì giới tư binh đoàn đoàn bao vây..']
                    },
                    168: {
                        'Hoạn quan tập đoàn': ['Trần Phồn, Đậu Vũ có ý đồ chính biến, ngươi phụ trách khóa chặt cung môn, nhưng Vũ Lâm quân bên ngoài điện đã bắt đầu dùng xe xung kích tông cửa.'],
                        'Ngoại thích sĩ tộc': ['Bí mật mưu giết hoạn quan bị lộ, Vương Phủ dẫn hơn ngàn giáp sĩ dồn ngươi và đồng liêu vào ngõ cụt, chuẩn bị giết chết tại chỗ.'],
                        'Quan vọng triều thần': ['Ngươi cố gắng giữ trung lập giữa yêm đảng và sĩ nhân, nhưng cả hai phái đồng thời nhận định ngươi là nội gián, thích khách đã lẻn vào nhà ngươi.'],
                        'Địa phương sĩ nhân': ['Họa đảng cố lan đến châu quận, vì ngươi từng bái phỏng Lý Ưng, đội lùng bắt của châu mục đang giăng lưới truy lùng ngươi.']
                    },
                    184: {
                        'Đại Hán triều đình': ['Chiến báo tiền tuyến bay về liên tục như tuyết rơi, quân Hoàng Cân tiến sát Tư Lệ, ngươi trong đêm mang theo ấn tín thiên tử hoảng loạn chạy trốn.'],
                        'Hoàng Cân quân': ['Trương Giác bệnh nặng ho ra máu, bùa nước mất linh, những tín đồ đói khát bắt đầu vung đao chém giết lẫn nhau để tranh giành ngụm kê cuối cùng.'],
                        'Triều đình thảo phạt quân': ['Đội hình của ngươi vấp phải cuộc xung phong cuồng nhiệt không sợ chết của Hoàng Cân lực sĩ, đội đốc chiến đã dựng sẵn máy chém ở phía sau.'],
                        'Địa phương hào cường': ['Loạn dân Hoàng Cân như châu chấu tràn ngập khắp núi đồi bao vây trang viên, ổ bảo của ngươi chỉ còn ba ngày lương thực và vài trăm người già yếu.']
                    },
                    189: {
                        'Đổng Trác quân': ['Ngươi phụng mệnh vào kinh tiếp quản Bắc quân, nhưng trên đường phố Lạc Dương lại hứng chịu những mũi tên bắn lén từ đám tàn binh và dân chúng cực kỳ thù hận lính Tây Lương.'],
                        'Quan Đông liên quân': ['Ngươi hưởng ứng lời kêu gọi chạy đến Toan Táo, giữa đường lương thảo bị quân bạn cướp sạch, binh lính sắp sửa làm phản.'],
                        'Đông Hán triều đình': ['Đổng Trác cưỡng ép phế truất Thiếu Đế, vì ngươi lộ vẻ không đành lòng trên triều đường, võ sĩ Tây Lương đã đợi sẵn ngoài cung môn để chém ngươi.'],
                        'Quan vọng phái': ['Lạc Dương bốc cháy ngùn ngụt, ngươi bị kẹt trong bức tường thành đang bốc cháy, ngoài cổng thành là thiết kỵ Tây Lương đang bắn tên bừa bãi.']
                    },
                    192: {
                        'Lương Châu phán quân': ['Lý Quách nội chiến, ngươi trên đường phố Trường An bị loạn binh coi là mục tiêu cướp bóc, ngay cả áo giáp da cũng bị lột sạch.'],
                        'Tào Tháo quân': ['Việc thu biên Thanh Châu binh khiến các cựu tướng bất mãn, trong lúc trấn áp binh biến, ngươi bị loạn binh Thanh Châu dồn đến bờ vực thẳm.'],
                        'Viên Thiệu quân': ['Tử chiến với Công Tôn Toản ở Giới Kiều, cơn mưa tên rợp trời của Bạch Mã Nghĩa Tòng đã bắn tấm khiên của ngươi trông như con nhím.'],
                        'Viên Thuật quân': ['Viên Thuật vơ vét của cải, trong quân ba ngày không có lương thực, ánh mắt các bộ tướng nhìn ngươi đã không còn giống nhìn người, mà là nhìn miếng thịt.'],
                        'Lưu Bị quân': ['Dựa dẫm Công Tôn Toản ở Bình Nguyên, khu vực phòng thủ của ngươi bị Tiên Đăng tử sĩ của quân Viên điên cuồng chọc thủng.'],
                        'Lưu Biểu quân': ['Tôn Kiên vượt sông đánh Lưu Biểu, ngươi mai phục ở Hiện Sơn, nhưng lại bị Trình Phổ đánh vòng bọc hậu cắt đứt đường lui.'],
                        'Tôn Sách quân': ['Tôn Kiên trúng tên lạc tử vong, trong lúc hộ tống linh cữu rút lui, ngươi vấp phải sự đánh chặn trùng trùng điệp điệp của thủy quân Kinh Châu.'],
                        'Lữ Bố quân': ['Vương Duẫn tử tiết Trường An thất thủ, ngươi theo Lữ Bố phá vây, bị mấy vạn thiết kỵ của Lý Giác truy sát trên đồng bằng như lùa thỏ.']
                    },
                    195: {
                        'Lưu Do quân': ['Binh phong của Tôn Sách cực thịnh, đại doanh của ngươi bị chọc thủng, đang chật vật chạy trốn giữa đám loạn quân.'],
                        'Tôn Sách quân': ['Trận đầu vượt sông đối mặt với cường địch phản công, ngươi bị bộ binh trọng giáp của Lưu Do bao vây chặt chẽ giữa vũng bùn lầy.'],
                        'Viên Thuật quân': ['Tôn Sách mượn binh thoát khỏi sự khống chế, ngươi với tư cách là giám quân phải đối mặt với nguy cơ bị Tôn Sách giết người diệt khẩu.'],
                        'Địa phương hào cường': ['Giang Đông môn phiệt mọc lên như nấm, ngươi bị ép phải chọn phe giữa hai đội quân giao chiến, chọn sai sẽ đối mặt với thảm họa diệt môn.']
                    },
                    196: {
                        'Tào Ngụy chính quyền': ['Nghênh phụng thiên tử khiến bảo hoàng đảng âm thầm liên kết, bức mật thư ngươi đánh chặn được cho thấy phó tướng của ngươi đã bị mua chuộc chuẩn bị tập kích doanh trại trong đêm.'],
                        'Viên Thiệu quân': ['Chủ công từ chối đón thiên tử làm mất tiên cơ, hai phái mưu sĩ Thư Thụ và Quách Đồ chèn ép lẫn nhau, ngươi vì đứng sai phe nên bị vu oan tội lớn.'],
                        'Viên Thuật quân': ['Viên Thuật tiếm quyền dẫn đến tứ diện Sở ca, trên phòng tuyến Hoài Nam, ngươi vừa đối mặt với đợt xung phong đầu tiên của kỵ binh Lữ Bố thì phòng tuyến đã sụp đổ.'],
                        'Lưu Bị quân': ['Lữ Bố thừa cơ ban đêm đánh lén Hạ Phì, gia quyến của ngươi toàn bộ rơi vào tay giặc, tàn quân bị Tịnh Châu Lang Kỵ truy đuổi trong bùn lầy.'],
                        'Lữ Bố quân': ['Ngươi đoạt lấy Từ Châu nhưng chưa đứng vững, cha con Trần Đăng âm thầm liên kết với Tào Tháo, kho lương nơi ngươi đóng quân bị thiêu rụi một cách khó hiểu.'],
                        'Kinh Châu Lưu Biểu': ['Trương Tú chiếm cứ Uyển Thành liên tục có động thái lạ, ngươi với tư cách là tướng giữ tiền đồn bị thiết kỵ Tây Lương quấy rối liên tục nửa tháng không thể chợp mắt.'],
                        'Giang Đông Tôn Sách': ['Tôn Sách bình định Giang Đông bằng thủ đoạn đẫm máu, tàn quân Nghiêm Bạch Hổ liên kết với Sơn Việt dùng tên tẩm độc bao vây ngươi trùng trùng điệp điệp trong rừng sâu núi thẳm.'],
                        'Ích Châu Lưu Chương': ['Triệu Vĩ phát động phản loạn ở Ba Quận, huyện thành của ngươi bị mấy vạn quân phản loạn bao vây, tường thành bị mưa lớn cuốn sập.'],
                        'Tây Lương Mã Đằng': ['Tàn đảng Lý Giác, Quách Dĩ rút vào Quan Trung, ngươi dưới trướng Mã Đằng phòng thủ ải khẩu, đối mặt với những kẻ cuồng tín cướp bóc không có giới hạn.'],
                        'Hán Trung Trương Lỗ': ['Ngươi thi hành Ngũ Đấu Mễ đạo vấp phải sự chống trả quyết liệt của hào cường địa phương, tế tửu bị ám sát, tín đồ đối mặt với sự trả thù đẫm máu.']
                    },
                    200: {
                        'Tào Tháo quân': ['Quan Độ cạn lương, ngươi đứng gác ba ngày trong vũng bùn lạnh giá, tin tức Hứa Du đến hàng thật giả khó phân, đại quân sắp sửa làm phản.'],
                        'Viên Thiệu quân': ['Ô Sào lửa cháy ngút trời, ngươi ở trận địa tiền tuyến được thông báo chủ soái không cứu lương thảo mà lại ra lệnh tấn công doanh trại kiên cố, quân tâm chớp mắt tan rã.'],
                        'Lưu Bị quân': ['Dựa dẫm Viên Thiệu chuốc lấy thảm bại, ngươi ở Nhữ Nam cố gắng thu thập tàn binh, nhưng lại bị Hổ Báo Kỵ của Tào Nhân càn quét như gặt lúa.'],
                        'Giang Đông Tôn thị': ['Tôn Sách bị ám sát trọng thương, hào tộc Giang Đông thừa cơ làm phản lớn, tòa thành cô lập của ngươi bị Sơn Việt và quân phản loạn cắt đứt mọi nguồn nước.'],
                        'Kinh Châu Lưu Biểu': ['Ngươi được phái đi chặn đánh Tào Tháo xuôi nam, đối mặt với tiên phong quân Tào vừa thắng trận Quan Độ, khí thế bừng bừng.'],
                        'Ích Châu Lưu Chương': ['Mâu thuẫn giữa Đông Châu binh và hào tộc bản địa trở nên gay gắt dẫn đến ẩu đả quy quy mô lớn, ngươi trên đường phố bị tên lạc bắn xuyên qua bắp chân.'],
                        'Tây Lương Mã Đằng': ['Tào Tháo bình định Trung Nguyên xong liền uy hiếp Quan Lũng, ngươi ở tiền tuyến liên tục bị trinh sát tinh nhuệ của Tào Ngụy bóp nghẹt.'],
                        'Hán Trung Trương Lỗ': ['Sứ giả của Tào Tháo mang đến chiếu thư nghiêm khắc, ngươi với tư cách là phái chủ chiến bị phái đầu hàng trong giáo dồn vào chân tường.']
                    },
                    202: {
                        'Giang Đông Tôn thị': ['Tôn Quyền kế vị chưa đứng vững, Lý Thuật làm phản ở Lư Giang, ngươi làm tiên phong dẹp loạn vấp phải sự chống trả ngoan cường, lương thảo không tiếp tế kịp.'],
                        'Giang Đông phán đảng': ['Lư Giang thành vỡ, Tôn Quyền hạ lệnh đồ thành, ngươi bị kẹt cứng trong vò thành đang bốc cháy, trên đầu là cơn mưa tên rợp trời.'],
                        'Tào Tháo quân': ['Viên Thiệu bệnh chết, ngươi ở Lê Dương đối mặt với sự phản công của Viên Thượng, Viên Đàm, đại quân sa lầy trong đầm lầy Hà Bắc.'],
                        'Lưu Bị quân': ['Làm khách ở Kinh Châu bị Lưu Biểu nghi kỵ, Thái Mạo âm thầm cắt đứt quân nhu Tân Dã của các ngươi, binh lính hoàn toàn không có áo rét.'],
                        'Kinh Châu Lưu Biểu': ['Ngươi cố gắng cân bằng thế lực giữa tông tộc và khách tướng, nhưng trong một buổi yến tiệc lại phát hiện trong rượu có cặn lạ.'],
                        'Ích Châu Lưu Chương': ['Bọn phản loạn Bàng Hy tuy đã bị dẹp yên, nhưng vì ngươi từng được hắn đề bạt, đang phải đối mặt với cuộc thanh trừng chính trị cực kỳ tàn khốc của châu mục.']
                    },
                    208: {
                        'Tào Tháo quân': ['Ô Lâm lửa cháy ngút trời, chiến thuyền của ngươi bị xích sắt khóa chặt, nhảy xuống sông thì chết đuối, ở lại thì chết cháy.'],
                        'Tôn Quyền quân': ['Tuy dùng lửa thiêu quân Tào nhưng tiền tuyến truy kích thương vong thảm trọng, ngươi trong đầm lầy vấp phải sự cắn trả điên cuồng của tử sĩ quân Tào.'],
                        'Lưu Bị quân': ['Trường Bản Pha đại hội bại, ngươi bị mười mấy vạn nạn dân cuốn theo, phía sau Hổ Báo Kỵ của Tào Thuần đang đâm trường mâu vào lưng ngươi.'],
                        'Kinh Châu quân': ['Lưu Tông hàng Tào, ngươi với tư cách là cựu tướng Kinh Châu cự tuyệt đầu hàng, bị thân tín của Thái Mạo trói gô giải đến doanh trại quân Tào.'],
                        'Ích Châu Lưu Chương': ['Sau trận Xích Bích thiên hạ chấn động, Trương Lỗ thừa cơ ồ ạt xuôi nam, ải khẩu của ngươi bị giáo chúng Ngũ Đấu Mễ tập kích ban đêm phá vỡ.'],
                        'Hán Trung Trương Lỗ': ['Ngươi cố gắng lấy lòng Tào Tháo nhưng bị từ chối, đại quân Tào Ngụy ở Quan Lũng đã áp sát biên giới, ngươi bị đẩy ra tiền tuyến nộp mạng.'],
                        'Tây Lương Mã Đằng': ['Mã Đằng bị triệu tập vào kinh chẳng khác nào giam lỏng, ngươi ở đại doanh Tây Lương đối mặt với các tướng lĩnh rắn mất đầu sắp sửa tàn sát lẫn nhau.']
                    },
                    211: {
                        'Lưu Bị quân': ['Ngươi theo quân vào Thục, đường tiếp tế kéo dài ba ngàn dặm, kho lương ở ải Gia Meng bị một trận hỏa hoạn khó hiểu thiêu rụi một nửa.'],
                        'Lưu Chương quân': ['Lưu Bị trở mặt tấn công Ích Châu, ngươi ở tiền tuyến đối mặt với những cựu binh dày dạn sa trường, quận binh dưới trướng vừa chạm trán đã tan vỡ.'],
                        'Tào Tháo quân': ['Mã Siêu, Hàn Toại khởi binh, ngươi ở bên bờ Vị Thủy vấp phải đợt xung phong trọng giáp của thiết kỵ Tây Lương, doanh trại chớp mắt bị san phẳng.'],
                        'Tây Lương quân': ['Trúng phản gián kế của Tào Tháo, Mã Siêu và Hàn Toại tàn sát lẫn nhau trong đại trướng, ngươi bị loạn binh hai phái cuốn vào chém giết lẫn nhau trong doanh trại.'],
                        'Hán Trung Trương Lỗ': ['Mã Siêu binh bại trốn vào Hán Trung, ngươi được phái đi giám sát Mã Siêu, nhưng lại bị thân vệ của hắn dùng đao hoàn thủ kề vào cổ.'],
                        'Tôn Quyền quân': ['Thừa dịp Tào Tháo tây chinh để tấn công Hợp Phì, đại quân gặp mưa bão dịch bệnh hoành hành, ngươi ngay cả sức lực nắm chặt trường mâu cũng đã mất.']
                    },
                    215: {
                        'Hợp Phì thủ quân': ['Mười vạn quân Ngô vây thành, Trương Liêu hạ lệnh tử chiến, ngươi bị biên chế vào tám trăm đội cảm tử, lùi bước là chém, phía trước là núi đao biển lửa.'],
                        'Đông Ngô đại quân': ['Tám trăm người của Trương Liêu chọc thủng đại trận, Tôn Quyền suýt bị bắt sống, ngươi ở bên cầu gãy Tiêu Dao Tân bị giẫm đạp rơi xuống nước sắp chết đuối.'],
                        'Tào Ngụy viện quân': ['Ngươi ngày đêm gấp rút chạy đến Hợp Phì, trên con đường lầy lội vấp phải quân Ngô mai phục, xe lương bị hủy sạch rơi vào tuyệt cảnh.'],
                        'Lưu Bị quân': ['Lấy sông Tương làm ranh giới đối đầu với Tôn Quyền, bạn ở trận địa tiền tuyến bị cung nỗ thủ của đồng minh cũ ngày đêm áp chế không ngóc đầu lên nổi.']
                    },
                    219: {
                        'Quan Vũ bắc phạt quân': ['Sau khi uy chấn Hoa Hạ bất ngờ bị Đông Ngô đâm sau lưng, ngươi theo Quan Vũ bại tẩu Mạch Thành, bốn bề đều là quân Ngô hát Sở ca làm loạn quân tâm của ngươi.'],
                        'Phàn Thành thủ quân': ['Sau khi nước ngập bảy đạo quân, Phàn Thành như một hòn đảo cô lập, ngươi trên bức tường thành bị ngâm mềm giết chiến mã lót dạ, bệnh dịch đã lan tràn trong thành.'],
                        'Đông Ngô thâu tập quân': ['Bạch y độ giang tuy thắng, nhưng tử trung của Quan Vũ trong thành Giang Lăng phát động chiến tranh đường phố thảm liệt, ngươi trong ánh lửa vấp phải sự phản công liều chết.'],
                        'Thượng Dung thủ quân': ['Lưu Phong, Mạnh Đạt thấy chết không cứu, sau khi Quan Vũ bại vong Lưu Bị nổi trận lôi đình, mật thám của Cẩm Y Vệ đã mang theo thòng lọng lẻn vào doanh trướng của ngươi.']
                    },
                    221: {
                        'Thục Hán đông chinh quân': ['Lưu Bị dốc toàn quốc đánh Ngô, Trương Phi bị đâm chết quân tâm dao động, ngươi trong cái nóng oi bức đẩy xe truy trọng nặng nề gian nan lội bộ trong hẻm núi.'],
                        'Đông Ngô phòng ngự quân': ['Quân Thục thế như chẻ tre liên tiếp phá vỡ mấy doanh trại, ngươi ở tiền tuyến Tỷ Quy bị cắt đứt đường lui, đối mặt với sự bao vây trùng trùng điệp điệp của bộ binh tinh nhuệ nước Thục.'],
                        'Tào Ngụy quan chiến quân': ['Triều đình hạ lệnh tọa thu ngư lợi, nhưng khu vực phòng thủ của ngươi đột nhiên bị quân Ngô mượn đường tập kích, cô quân kiên thủ không có viện binh.']
                    },
                    225: {
                        'Thục Hán nam chinh quân': ['Tiến sâu vào vùng đất cằn cỗi gặp phải suối độc chướng khí, chiến hữu của ngươi sau khi uống nước cổ họng lở loét chết thảm, một lượng lớn binh lính xuất hiện triệu chứng sốt cao.'],
                        'Nam Trung phán quân': ['Đại quân Gia Cát Lượng thế như chẻ tre, Cao Định bị giết, bộ lạc của ngươi bị cắt đứt trong rừng sâu chỉ còn ba ngày lương thực.'],
                        'Mạnh Hoạch bộ chúng': ['Nhiều lần chiến bại khiến các thủ lĩnh bộ lạc hoàn toàn mất đi ý chí chiến đấu, ngươi trong lúc chủ trương tử chiến bị tộc nhân trói lại chuẩn bị dâng hàng.']
                    },
                    228: {
                        'Thục Hán bắc phạt quân': ['Mã Tốc thất thủ Nhai Đình, ngươi với tư cách là tàn quân bọc hậu trên đường núi chật hẹp, đối mặt với sự nghiền ép lặp đi lặp lại của mấy vạn trọng kỵ binh của Trương Cáp.'],
                        'Tào Ngụy tây tuyến quân': ['Gia Cát Lượng đột nhiên xuất Kỳ Sơn, ba quận Lũng Hữu làm phản đầu hàng, tòa thành cô lập của ngươi bị liên nỗ quân Thục phong tỏa trùng trùng điệp điệp mười ngày không có viện binh.']
                    },
                    234: {
                        'Thục Hán bắc phạt quân': ['Gia Cát Lượng bệnh chết ở Ngũ Trượng Nguyên, đại quân bí mật không phát tang rút lui, ngươi trong đêm tối yểm trợ chủ lực, vấp phải sự thăm dò truy kích điên cuồng của quân Ngụy.'],
                        'Tào Ngụy tây tuyến quân': ['Tư Mã Ý hạ lệnh kiên thủ không chiến, trong doanh trại bùng phát bệnh thương hàn nghiêm trọng, ngươi mỗi ngày kéo ra mấy chục thi thể chôn cất, bản thân cũng bị sốt cao.'],
                        'Thục Hán nội đấu phái': ['Ngụy Diên và Dương Nghi tàn sát lẫn nhau, ngươi đứng trước trận tuyến hai quân, bất kể nghe theo tướng lệnh của ai, đều phải đối mặt với tội liên đới phản quốc.']
                    },
                    238: {
                        'Thục Hán quân': ['Tưởng Uyển chủ chính nghỉ ngơi lấy sức, ngươi với tư cách là tướng lĩnh phái bắc phạt cấp tiến bị tước binh quyền, Hiệu Sự Phủ đang giám sát chặt chẽ nhất cử nhất động của ngươi.'],
                        'Tào Ngụy tây tuyến quân': ['Quân Thục bày binh thị uy ở Hán Trung, biên quan nơi ngươi đóng quân quanh năm không có lương thực, quân phòng thủ đã chuẩn bị giết tướng dâng thành đầu hàng.'],
                        'Tào Ngụy viễn chinh quân': ['Tư Mã Ý viễn chinh Liêu Đông gặp mưa bão liên miên nhiều tháng, đất bằng tích nước sâu vài thước, ngươi mỗi ngày trong vũng bùn nhìn đồng liêu chết vì mất nhiệt.']
                    },
                    249: {
                        'Tư Mã thị': ['Sự biến Cao Bình Lăng phát động, ngươi theo ba ngàn tử sĩ phong tỏa võ khố, nếu Tào Sảng quyết tâm phản công, ngươi sẽ phải đối mặt với sự trấn áp đẫm máu của quân chủ lực.'],
                        'Tào Sảng đảng vũ': ['Tư Mã Ý chỉ Lạc Thủy thề thốt nhưng chớp mắt trở mặt, ngươi với tư cách là thân tín bị đình úy bao vây trùng trùng điệp điệp, họa diệt môn chỉ trong chốc lát.'],
                        'Tào Ngụy tông thất': ['Đại quyền rơi vào tay kẻ khác, ngươi bị ra lệnh giam lỏng ở Nghiệp Thành, thị vệ bên cạnh toàn bộ đổi thành thích khách của Tư Mã thị, trong thức ăn thức uống thoang thoảng mùi thuốc.'],
                        'Quan vọng trung lập phái': ['Triều cục xáo trộn lớn, ngươi vì từ chối ký tên vào tấu chương liên danh thảo phạt Tào Sảng, bị mật thám vu oan tội danh tống vào ngục tối.']
                    },
                    251: {
                        'Tào Ngụy triều đình quân': ['Vương Lăng mưu phản tuy đã bị phá, nhưng đảng vũ trong quân bám rễ sâu xa, ngươi đang bị thẩm tra sàng lọc, sống chết khó lường.'],
                        'Hoài Nam phán quân': ['Vương Lăng khởi sự không thành bị ép tự sát, đại quân chớp mắt làm phản tan rã, ngươi dưới trường thương của quân truy kích không lối thoát.'],
                        'Đông Ngô trận doanh': ['Vốn định thừa dịp Hoài Nam đại loạn kiếm chác lợi lộc, nhưng lại vấp phải sự phòng thủ nghiêm ngặt của quân Ngụy, lúc rút lui gặp mai phục bên bờ sông.']
                    },
                    252: {
                        'Đông Ngô quân': ['Đại quân Gia Cát Khác phá Ngụy ở Đông Hưng, nhưng tiền tuyến tranh công dẫn đến các doanh trại cướp đoạt chiến lợi phẩm, ngươi suýt chết dưới đao của đồng liêu.'],
                        'Tào Ngụy quân': ['Trận Đông Hưng cầu phao đứt gãy đại quân hội bại, ngươi bị chen lấn rơi xuống dòng nước sông lạnh thấu xương, xung quanh toàn là tiếng kêu gào tuyệt vọng.'],
                        'Thục Hán quân': ['Khương Duy xuất binh phối hợp vấp phải sự đánh chặn của Quách Hoài, đường tiếp tế bị kỵ binh tinh nhuệ quân Ngụy cắt đứt hoàn toàn.']
                    },
                    253: {
                        'Đông Ngô quân': ['Hợp Phì tân thành đánh mãi không hạ được, trong quân dịch bệnh hoành hành, ngươi cả người nóng ran nhưng vẫn bị ép vác vân đài xung phong.'],
                        'Tào Ngụy quân': ['Hợp Phì tân thành quân phòng thủ không đủ, tường thành sắp sụp đổ, ngươi với tư cách là tướng giữ thành được thông báo sẽ không có viện quân nữa.']
                    },
                    255: {
                        'Tào Ngụy triều đình quân': ['Tư Mã Sư mang bệnh thân chinh Hoài Nam, ngươi ở tiền tuyến cường công Thọ Xuân, vấp phải sự chống trả quyết tử của quân tinh nhuệ Vô Khâu Kiệm thương vong thảm trọng.'],
                        'Hoài Nam phán quân': ['Vô Khâu Kiệm binh bại Hạng Thành, ngươi với tư cách là tàn quân phản loạn trốn vào rừng sâu, không có lương thảo, còn phải đối mặt với cuộc giăng lưới truy lùng của triều đình.'],
                        'Đông Ngô viện quân': ['Văn Khâm đến hàng, bộ đội tiền tuyến của ngươi vì thiếu hụt tiếp tế bắt đầu cướp bóc thôn làng, quân kỷ đối mặt với sự sụp đổ hoàn toàn.'],
                        'Thục Hán quân': ['Khương Duy đại thắng ở Thao Tây, ngươi với tư cách là tiên phong truy kích quân Ngụy, vấp phải sự mai phục của lực lượng dự bị quân Ngụy.'],
                        'Thục Hán bắc phạt quân': ['Sau đại thắng Thao Tây Khương Duy cô quân tiến sâu vào Địch Đạo, ngươi trong đống tuyết cạn kiệt lương thảo, chỉ có thể gặm nhấm tủy xương của xác chiến mã.'],
                        'Tào Ngụy tây tuyến quân': ['Vương Kinh đại bại ở Thao Tây thương vong mấy vạn, ngươi bị kẹt trong tòa thành cô lập Địch Đạo, ngoài không có viện binh, trong có thương binh kêu la.']
                    },
                    257: {
                        'Tào Ngụy triều đình quân': ['Vây công Thọ Xuân gặp mưa lớn nhiều tháng, doanh trướng của ngươi ngập nước đến eo, dịch bệnh liên miên và sự mệt mỏi đang tàn phá quân tâm.'],
                        'Hoài Nam phán quân': ['Trong thành Thọ Xuân người ăn thịt người, Gia Cát Đản hạ lệnh không được ra khỏi thành, ngươi trong tuyệt vọng suy nghĩ xem có nên mở cổng thành đầu hàng trong đêm hay không.'],
                        'Đông Ngô viện quân': ['Bị vây trong thành Thọ Xuân trở thành cá nằm trên thớt, quân Ngụy ngoài thành lũy sừng sững, mỗi lần phá vây đều biến thành một cuộc đồ sát.']
                    },
                    263: {
                        'Tào Ngụy phạt Thục quân': ['Đặng Ngải vượt lén Âm Bình, bảy trăm dặm núi cao vực sâu không bóng người, ngươi trong cơn đói khát tột độ quấn chăn nỉ lăn từ vách đá xuống sống chết chưa rõ.'],
                        'Thục Hán phòng ngự quân': ['Gia Cát Chiêm tử chiến ở Miên Trúc, phòng tuyến Thành Đô của ngươi sụp đổ toàn diện, Hậu Chủ đã chuẩn bị sẵn quan tài ra hàng, ngươi không còn đường lui.'],
                        'Đông Ngô viện quân': ['Ngươi phụng mệnh cứu viện Thục Hán, vừa đến Ba Đông liền hay tin Lưu Thiện đầu hàng, đại quân rơi vào tử cục tiến thoái lưỡng nan, bị quân Tấn bao vây.']
                    },
                    264: {
                        'Đông Ngô triều đình': ['Tôn Hạo kế vị từ minh quân đột ngột biến thành bạo chúa, ngươi vì dâng sớ can gián thẳng thắn, đình úy đang chuẩn bị móc hai mắt và lột da mặt ngươi.'],
                        'Tây Tấn sơ lập': ['Chung Hội, Đặng Ngải tranh công ở Thục Trung bùng nổ binh biến quy mô lớn, ngươi trong đám loạn quân bị những binh lính đỏ mắt dồn vào ngõ cụt.'],
                        'Thục Hán tàn thần': ['Nước mất nhà tan, Khương Duy trá hàng kế bại thân tử, ngươi với tư cách là cựu thần bị cưỡng ép di dời đến Lạc Dương, dọc đường dịch bệnh hoành hành cửu tử nhất sinh.']
                    },
                    280: {
                        'Tây Tấn diệt Ngô quân': ['Lâu thuyền của Vương Tuấn xuôi dòng mà xuống, ngươi trên chiến thuyền tiên phong vấp phải ám tiêu chông sắt trên mặt sông Đông Ngô, đáy thuyền bị chọc thủng nước sông tràn vào điên cuồng.'],
                        'Đông Ngô mạt lộ quân': ['Kiến Nghiệp thành vỡ, đại quân vừa chạm trán đã tan vỡ, ngươi với tư cách là tướng lĩnh tử trung bị bộ binh trọng giáp quân Tấn bao vây trùng trùng điệp điệp, yêu cầu ngươi tự vẫn.'],
                        'Tam phương dư thần': ['Thiên hạ nhất thống, ngươi với tư cách là cựu thần tiền triều không những không được phong thưởng, ngược lại bị tân quý cướp đoạt điền sản, cả nhà già trẻ lưu lạc đầu đường xó chợ.']
                    },
                    290: {
                        'Tây Tấn triều đình': ['Tấn Vũ Đế băng hà, Dương Tuấn phụ chính chuyên quyền, Giả Hậu mật mưu chính biến, ngươi trong cấm quân bị ép phải chọn phe, chọn sai sẽ bị diệt tộc.'],
                        'Ngoại trấn đô đốc': ['Bát vương chi loạn sóng ngầm cuộn trào, triều đình lấy việc cắt đứt quân lương để ép tước quyền, kiêu binh hãn tướng dưới trướng ngươi vì thiếu lương đã chuẩn bị làm phản.']
                    }
                }
            },
            classSpecific: {
                'Chính Sử': {
                    'Di lão cô thần': ['Cố quốc diệt vong cự tuyệt đầu hàng kẻ địch, đặc sứ tân triều đưa tới ba thước lụa trắng, không tự sát sẽ bị tru di tam tộc.'],
                    'Tàn binh bại tướng': ['Chủ tướng tử trận đội ngũ cạn lương trong rừng sâu, có người đề nghị giết thương binh để tiết kiệm khẩu phần ăn, binh biến chỉ trong gang tấc.'],
                    'Tử chiến chi sĩ': ['Không còn đường lui cắn đứt ngón tay thề tử chiến, nhưng xe phá thành nặng nề đã tông nát bét cổng thành.'],
                    'Ẩn thế di dân': ['Quan lại tân triều lục soát từng nhà bắt tàn dư tiền triều, khẩu âm của ngươi gây nghi ngờ, thư tố giác đã được gửi đến huyện nha.'],
                    'Vong quốc cựu thần': ['Cái mũ tàn dư tiền triều bất cứ lúc nào cũng có thể khiến ngươi bị tru di cả nhà trong cuộc thanh trừng chính trị.'],
                    'Sơn lâm ẩn sĩ': ['Quân phiệt vì ép ngươi ra làm quan đã phóng hỏa đốt trụi cả ngọn núi, cắt đứt mọi con đường sống của ngươi.'],
                    'Tản binh du dũng': ['Lên núi làm cướp bị triều đình coi là mối họa lớn, trọng binh càn quét sơn trại bị phá, tù binh đều bị chôn sống.'],
                    'Lưu vong bộ chúng': ['Lưu lạc khắp nơi bị lực lượng vũ trang địa phương bao vây, không lương không thuốc vết thương lở loét, chỉ có thể ngồi chờ chết.'],
                    'Bại quân chi tướng': ['Mất thành mất đất chỉ mang theo thân tín bỏ trốn, phó tướng vì muốn lấy đầu ngươi đổi tiền thưởng đã hạ độc trong bình nước.'],
                    'Ẩn thế cao nhân': ['Thảo đường trong núi sâu bị đám tàn binh đói đỏ mắt phát hiện, hai thanh đao đẫm máu kề cổ bức cung giấu vàng bạc.'],
                    'Lục lâm du hiệp': ['Cướp của người giàu chia cho người nghèo vô tình cướp được cơ mật quân sự, dẫn đến sự bao vây điên cuồng không tiếc giá nào của quân chính quy.'],
                    'Tị loạn thương cổ': ['Vận chuyển vật tư bị đám tàn binh tiền tuyến nhắm tới, hàng hóa bị cướp sạch, gia quyến đi cùng cũng đang trong tình thế ngàn cân treo sợi tóc.'],
                    'Bạch y thương cổ': ['Cải trang lẻn vào trọng trấn bị hiệu sự phát hiện, một khi bị bắt lột da trong ngục tối, hạm đội tập kích sẽ bị tiêu diệt toàn quân.'],
                    'Trì tiết sứ thần': ['Hai nước giao ác, quân chủ nước địch nổi giận xé nát quốc thư, muốn ném ngươi vào vạc dầu nấu chín để tế cờ.'],
                    'Khách tướng': ['Ăn nhờ ở đậu chiến bại bị lôi ra làm dê thế tội, trường đao của đội đốc chiến đã kề trên cổ.'],
                    'Khách quân sĩ tốt': ['Tác chiến nơi đất khách quê người ngôn ngữ bất đồng, chiến bại tan rã ngay cả hỏi đường cũng không được, bị bách tính coi như giặc cướp mà săn lùng.'],
                    'Giải phiền đốc tướng': ['Khách quân thủy thổ không phục nhiễm chướng khí, tướng giữ thành địa phương không cho thuốc men còn bắt các ngươi làm bia đỡ đạn đẩy ra tiền tuyến.'],
                    'Khách quân bộ khúc': ['Lương thảo cạn kiệt quân bạn từ chối tiếp tế, ánh mắt của binh lính đói khát nhìn ngươi giống như đang nhìn một miếng thịt tươi.'],
                    'Trì viện kiêu tướng': ['Ngày đêm gấp rút người mệt ngựa mỏi, trong hẻm núi hiểm trở vấp phải sự mai phục tinh nhuệ nhất của quân địch.'],
                    'Đông chinh chủ soái': ['Giang phòng bị phá đại quân hội bại, soái hạm của ngươi bị hỏa thuyền bao vây, quân truy kích phía sau đã cắt đứt đường lui.'],
                    'Bắc phạt chủ soái': ['Lúc tiền tuyến đại thắng, chủ bạ phía sau ăn bớt lương thảo báo cáo sai quân tình, hoàng đế liên tiếp hạ ba đạo kim bài triệu ngươi hồi triều.'],
                    'Viễn chinh quân chủ soái': ['Đường vận lương bị lực lượng vũ trang du kích cắt đứt hoàn toàn, các tướng lĩnh âm mưu chém đầu ngươi để đổi lấy con đường sống.'],
                    'Nam phạt đại tướng': ['Nam chinh gặp chướng khí dịch bệnh mỗi ngày chết mấy trăm người, chiếu thư giục chiến từ hậu phương như bùa đòi mạng.'],
                    'Bình Thục đại đô đốc': ['Kẻ thù chính trị sàm tấu nói ngươi muốn ủng binh tự lập, giám quân mang theo mật chỉ tước binh quyền đã đến đại doanh.'],
                    'Viễn chinh sĩ tốt': ['Thủy thổ không phục nhiễm bệnh sốt rét ác tính, quân y thiếu thốn, nhìn đồng hương chết trong cơn co giật đau đớn tột cùng.'],
                    'Cô thành thủ tướng': ['Quân địch tuyên bố thành vỡ sẽ đồ thành ba ngày, trong không lương thảo ngoài không viện binh, bách tính dùng ánh mắt khác thường nhìn ngươi.'],
                    'Thủ thành chủ tướng': ['Quân địch ném xác chết nhiễm bệnh vào trong thành, nguồn nước bị cắt, thân vệ của ngươi âm mưu trói ngươi để đổi lấy thuốc giải.'],
                    'Thủ thành sĩ tốt': ['Tường thành bị máy bắn đá đập sập, không có binh khí chỉ có thể giơ tay chân đứt lìa của đồng liêu lên đỡ những mũi tên bay tới.'],
                    'Biên cảnh thủ tướng': ['Đại quân nước láng giềng tập kích, trong tay ngươi chỉ có người già yếu bệnh tật, thứ sử lại mang theo gia quyến bỏ trốn trong đêm.'],
                    'Trấn bắc thủ tướng': ['Du kỵ binh dị tộc đột nhiên xuôi nam gõ cửa ải, tường thành lâu năm không sửa chữa, khói lửa báo động bị mưa lớn dập tắt.'],
                    'Đại đô đốc': ['Phòng tuyến bị xé toạc hoàn toàn, soái hạm do ngươi đích thân đốc chiến bị đục thủng đáy, nước sông điên cuồng tràn vào.'],
                    'Trung quân đô đốc': ['Kinh thành bùng nổ binh biến, hoàng đế bị bắt cóc, một nửa cấm quân làm phản chĩa đồ đao thẳng vào doanh trướng của ngươi.'],
                    'Ngoại trấn đô đốc': ['Triều đình nghi kỵ binh quyền của ngươi âm thầm cắt đứt quân lương, kiêu binh hãn tướng vì thiếu lương chuẩn bị binh biến.'],
                    'Thủy quân đô đốc': ['Thượng nguồn bị lâu thuyền khổng lồ phong tỏa, phó đô đốc từ chối thi hành mệnh lệnh và giữ lại toàn bộ hỏa thuyền.'],
                    'Châu quận đốc tướng': ['Châu quận bị quân phiệt tiếp quản, võ tướng thù hận cựu tướng, hơi có chút không tuân lệnh liền bị chém đầu theo quân pháp.'],
                    'Vận lương quan': ['Mưa bão cuốn trôi sạn đạo quân lương không thể đưa đến, trễ hạn sẽ bị chém, ngươi phải gom đủ mười vạn thạch lương thảo trong ba ngày.'],
                    'Vận lương dân phu': ['Đẩy mộc ngưu lưu mã lội bộ trên đường núi lầy lội, bị khinh kỵ binh cướp lương chỉ có thể dùng đòn gánh chống cự.'],
                    'Tùy quân tham quân': ['Ngươi phát hiện chủ bạ âm thầm cấu kết với quân địch, thích khách truy sát ngươi đã lẻn vào doanh trướng, quân quy và tư hình đang đến gần.'],
                    'Đại hiền lương sư': ['Chủ lực nghĩa quân bị bao vây tiêu diệt gần hết, ngươi bệnh nặng ho ra máu, cái đầu bị treo thưởng chức vạn hộ hầu.'],
                    'Phương trấn cừ soái': ['Chủ lực Hoàng Cân bị tiêu diệt, ngươi dẫn tàn quân trốn trong núi, mưa bão liên miên lương thảo ẩm mốc binh biến sắp xảy ra.'],
                    'Hoàng Cân lực sĩ': ['Sự tẩy não của bùa nước tan biến, đối mặt với chiến thuật chém đầu tàn nhẫn của quân Hán, đội hình sụp đổ hoàn toàn.'],
                    'Tầm thường giáo chúng': ['Tế tửu cuỗm tiền bỏ trốn ngươi đói đến phát hoảng, còn phải đối mặt với cuộc thanh trừng đồ thôn vô nhân đạo của quân chính quy.'],
                    'Man hoang động chủ': ['Đại quân áp sát biên giới, mấy tên động chủ nhỏ chuẩn bị thừa cơ ban đêm chém đầu ngươi đi tranh công.'],
                    'Đằng giáp binh': ['Gặp phải hỏa công, bộ giáp mây tẩm đẫm dầu trong nháy mắt bốc cháy dữ dội, ngươi biến thành một ngọn đuốc sống gào thét trong tuyệt vọng.'],
                    'Tượng binh': ['Voi khổng lồ hoảng sợ phát điên giẫm đạp người phe mình, ngươi ngã khỏi lưng voi, móng voi nặng vài tấn giẫm mạnh xuống.'],
                    'Khương tộc thủ lĩnh': ['Bộ lạc gặp bão tuyết trâu bò cừu chết cóng, quân phiệt người Hán cưỡng ép trưng dụng các ngươi đi làm bia đỡ đạn lấp hào.'],
                    'Sơn Việt hào tù': ['Đại quân Đông Ngô phóng hỏa đốt núi, tộc nhân của ngươi ngã gục trong làn khói đặc, ải khẩu xuống núi bị cường nỗ phong tỏa.'],
                    'Phán trấn thủ lĩnh': ['Đại quân dẹp loạn đến sớm, các thứ sử hứa hẹn hưởng ứng toàn bộ đều đứng nhìn, tòa thành cô lập không có viện binh.'],
                    'Hiếp tòng tướng tá': ['Bị ép mù quáng đi theo phản loạn, đại thế đã mất triều đình cự tuyệt đầu hàng, ngươi bị dồn vào tuyệt cảnh.'],
                    'Đảo qua tử sĩ': ['Phản loạn thất bại trở thành con cờ bị vứt bỏ, đại quân triều đình bao vây bốn phía cự tuyệt đầu hàng, chỉ có thể trong tuyệt vọng bị vạn tiễn xuyên tâm.'],
                    'Hoài Nam cựu bộ': ['Phản loạn thất bại bị đại quân bao vây, không chấp nhận đầu hàng, hoặc là tuyệt vọng tự vẫn hoặc là bị vạn tiễn xuyên tâm.'],
                    'Ngũ Đấu Mễ đạo': ['Tế tửu bị quân phiệt mua chuộc, ép buộc tín đồ mặc chiến giáp làm bia đỡ đạn, không đi liền bị khai trừ khỏi giáo tịch chịu khổ địa ngục.'],
                    'Cát cứ thủ lĩnh': ['Cường địch vây thành, đại tướng thống binh mà ngươi tin tưởng nhất đã âm thầm làm phản chuẩn bị dâng thành.'],
                    'Chư hầu minh chủ': ['Liên quân mỗi người một bụng dạ, trong doanh trại hai lộ chư hầu vì tranh giành lương thảo đã rút đao tàn sát lẫn nhau.'],
                    'Các lộ chư hầu': ['Thực lực của ngươi yếu kém bị ép tham chiến, tiên phong bị tiêu diệt, minh chủ lại ra lệnh cho ngươi tiếp tục xông lên nộp mạng.'],
                    'Tọa sơn quan hổ đấu chi quân': ['Hai bên giao chiến đột nhiên đạt được thỏa thuận đình chiến, quyết định liên thủ nuốt chửng địa bàn của ngươi trước.'],
                    'Đương địa thổ hào': ['Quân phản loạn do ngươi tài trợ bị tiêu diệt, bộ đội dẹp loạn đang theo danh sách từng nhà tịch thu tài sản diệt tộc.'],
                    'Ích Châu hào cường': ['Chính quyền ngoại lai thi hành Thục khoa hà khắc, ngươi vì giấu giếm hộ khẩu bị tước đoạt điền sản lưu đày biên cương.'],
                    'Lương Châu hào tộc': ['Quân phiệt hỗn chiến lan đến lãnh địa, ổ bảo bị thiết kỵ Tây Lương bao vây, nguồn nước bị cắt đứt bảy ngày.'],
                    'Liêu Đông hào tộc': ['Viễn chinh quân phá thành, để răn đe vùng đất ngoài vòng giáo hóa, hạ lệnh chôn sống nam đinh từ mười lăm tuổi trở lên.'],
                    'Công Tôn thị tông tộc': ['Đại quân nước địch bao vây trùng trùng điệp điệp, trong thành đã xuất hiện thảm cảnh người ăn thịt người, các tướng lĩnh nòng cốt của tông tộc càng bị kẻ phản bội ám sát.'],
                    'Châu mục thân tộc': ['Châu mục bệnh chết, chú bác của ngươi vì tranh giành quyền thừa kế đã dẫn ngoại binh vào thành, trong thành bắt đầu cuộc tắm máu.'],
                    'Công khanh đại thần': ['Đại tướng quân vừa bị giết, giáp sĩ của Chấp Kim Ngô bao vây phủ đệ của ngươi, nếu không viết thư nhận tội sẽ lập tức bị diệt môn.'],
                    'Hán thất tông thân': ['Ngươi bị quyền thần lấy danh nghĩa mưu phản tước phiên, hộ vệ toàn bộ đổi thành thích khách, thức ăn thức uống tỏa ra mùi thuốc.'],
                    'Tông thất quyền thần': ['Độc ôm đại quyền dẫn đến huyết chiếu của hoàng đế, thiết kỵ thanh trừng gian thần đã phá vỡ phòng tuyến kinh thành.'],
                    'Bá phủ quyền thần': ['Ngươi vừa trừ khử kẻ thù chính trị, lại phát hiện túc vệ trung quân đã bị tàn đảng của kẻ thù thâm nhập khống chế toàn bộ.'],
                    'Tư Mã thị tông vương': ['Bát vương chi loạn sóng ngầm cuộn trào, anh em ruột của ngươi sắp xếp rượu độc trong yến tiệc và xúi giục đô đốc của ngươi làm phản.'],
                    'Khai quốc huân quý': ['Thỏ khôn chết chó săn bị nấu, hoàng đế thanh trừng lão thần, ngươi bị vu oan tội tham ô quân lương tước đoạt tước vị.'],
                    'Hán thất cựu thần': ['Việc ngươi âm thầm liên lạc với bảo hoàng đảng bị bại lộ, thích khách của bá phủ đã lẻn vào thư phòng của ngươi.'],
                    'Trung thường thị': ['Của cải của ngươi bị điều tra rõ ràng, hoàng đế hạ lệnh tống ngươi vào tàm thất, các con nuôi toàn bộ trở mặt.'],
                    'Tiểu hoàng môn': ['Đại thái giám thất thế, ngươi bị lôi ra ngoài cung môn, các thái học sinh đang điên cuồng ném đá vào ngươi.'],
                    'Hoạn quan đảng vũ': ['Các quan viên thanh lưu liên kết ép cung, ngươi với tư cách là nanh vuốt của yêm đảng bị lôi ra chợ chuẩn bị đánh chết bằng gậy.'],
                    'Yêm đảng thân tín': ['Sĩ tộc địa phương phát động bạo loạn, huyện nha bị phá vỡ, bạo dân yêu cầu thắp thiên đăng ngươi.'],
                    'Đại tướng quân': ['Hoạn quan ra tay trước bắt cóc thái hậu đóng chết cung môn, trên tường thành toàn là ám tiễn, bộ tướng lặng lẽ lùi lại.'],
                    'Ngoại thích tử đệ': ['Chỗ dựa ngoại thích sụp đổ, ngươi bị tước đoạt đặc quyền, gông cùm của đình úy đã tròng vào cổ ngươi.'],
                    'Gián ngôn mưu thần': ['Ngươi liều chết can gián không được xuất binh, chủ công nổi giận tống ngươi vào ngục, đại quân nếu bại ngươi chắc chắn bị lôi ra chém đầu.'],
                    'Mạc phủ mưu sĩ': ['Kế sách của ngươi dẫn đến đại bại, chủ công vì dập tắt sự oán hận của quân lính, sai người bưng tới một ly rượu độc.'],
                    'Dĩnh Xuyên mưu sĩ': ['Chính sách đo đạc ruộng đất của ngươi chọc giận hào cường địa phương, tử sĩ đã giăng sẵn dây vấp ngựa trên đường về.'],
                    'Trần Cung đẳng mưu sĩ': ['Chủ công từ chối nghe lời can gián trung thành binh bại bị bắt, ngươi đối mặt với sự khuyên hàng của kẻ địch, chỉ có vươn cổ chịu chém để giữ trọn danh tiết.'],
                    'Tiên phong quan': ['Cô quân tiến sâu vấp phải chủ lực quân địch bao vây, bản đội phía sau lại án binh bất động thấy chết không cứu.'],
                    'Tiên phong hãn tướng': ['Chém tướng địch trên trận lại bị chủ soái ghen tị, bị phái đi lấp hào nộp mạng, rõ ràng là muốn mượn đao giết người.'],
                    'Tiên đăng mãnh tướng': ['Người đầu tiên xông lên tường thành, vân đài phía sau bị đập gãy, ngươi đơn độc rơi vào vòng vây trùng trùng điệp điệp.'],
                    'Đông chinh tiền phong': ['Trong doanh trại liên hoàn vấp phải hỏa hoạn tập kích, tiền phong doanh của ngươi chớp mắt bị cắt đứt đường lui hóa thành biển lửa.'],
                    'Phục cừu mãnh tướng': ['Giết đến đỏ mắt cô quân truy kích quá sâu, bị quân Ngô dụ vào vòng mai phục trong thung lũng, đá tảng đã bịt kín đường lui.'],
                    'Quân trung mãnh tướng': ['Lúc xông trận chiến mã bị dây vấp ngựa làm vấp ngã, trọng giáp đè lên người không thể đứng dậy, trường mâu đã đâm tới.'],
                    'Ngoại tính hãn tướng': ['Vì xuất thân thấp hèn bị các tướng lĩnh tông thất chèn ép, bị sắp xếp bọc hậu ở tử địa nguy hiểm nhất không có viện quân.'],
                    'Lương Châu hãn tướng': ['Chủ soái trúng phản gián kế tàn sát lẫn nhau, ngươi kẹt giữa hai phái đang chém giết trong doanh trại không biết nên vung đao về phía ai.'],
                    'Hà Bắc hãn tướng': ['Bộ binh trọng giáp bị khinh kỵ binh thả diều kéo lê đến kiệt sức, ngươi ngay cả vạt áo của kẻ địch cũng không chạm tới được.'],
                    'Tông tộc đại tướng': ['Chủ công bại lui mất tích, ngươi phải dẫn tàn binh chống đỡ mấy vạn quân truy kích, nếu chủ công tử vong ngươi sẽ bị ban chết.'],
                    'Ngoại lai khách tướng': ['Ăn nhờ ở đậu bị phái bản địa chèn ép, lúc chiến bại ngươi bị trói lại làm dê thế tội để dập tắt sự oán hận của quân lính.'],
                    'Ngũ hổ thượng tướng': ['Công cao chấn chủ rước lấy sự ghen ghét của các bên, ngươi ở tiền tuyến tắm máu chiến đấu, hậu phương lại cắt đứt lương thảo viện quân.'],
                    'Bát kiện tướng': ['Chủ công chìm đắm trong tửu sắc không nghe lời khuyên, thành trì bị ngập, chiến mã của ngươi ngâm trong nước không thể xung phong.'],
                    'Hoài Nam thượng tướng': ['Chủ công tiếm quyền dẫn đến tứ diện thụ địch đại quân không có ý chí chiến đấu, vấp phải đợt xung phong đầu tiên liền tháo chạy toàn tuyến.'],
                    'Hoài Tứ cựu tướng': ['Cùng với sự trỗi dậy của sĩ tộc bản địa ngươi bị gạt ra rìa, một trận thua nhỏ liền bị vu oan tội lớn tống vào ngục tối.'],
                    'Cảm tử duệ sĩ': ['Làm tử sĩ lấp hào đợt đầu tiên, phía sau là đồ đao của đội đốc chiến, phía trước là gỗ lăn nước sôi trút xuống.'],
                    'Trung quân duệ sĩ': ['Tiến sâu vào vùng bụng của nước địch gặp mai phục, đường vận lương bị đứt, ngươi mỗi ngày dựa vào việc gặm nhấm vỏ cây và xương ngựa chết để duy trì việc đứng vững.'],
                    'Túc vệ cấm quân': ['Quyền thần dẫn binh ép cung, ngươi kiên thủ cung môn, đồng liêu lại lén mở cửa hông, giáp sĩ phản loạn tràn vào đại điện.'],
                    'Tinh nhuệ nha binh': ['Chủ soái tử trận quân địch hô to giết sạch thân vệ, ngươi bị mấy chục tên lính địch đỏ mắt bao vây chặt chẽ.'],
                    'Giang Đông bộ khúc': ['Theo chủ tướng tiến sâu vào cảnh địch gặp mai phục, chủ tướng bỏ trốn, các ngươi bị vứt bỏ trong thung lũng đối mặt với ngọn đuốc rợp núi.'],
                    'Trung quân tinh kỵ': ['Đường dài bôn tập ngựa gầy rộc, chủ tướng hạ lệnh chém giết kỵ binh mất ngựa để tiết kiệm lương thực, móng ngựa của ngươi vừa vặn bị lở loét.'],
                    'Hổ Báo Kỵ': ['Truy kích sa vào đầm lầy, chiến mã không thể rút chân ra, hai bên vách núi xuất hiện mấy ngàn cường nỗ tinh nhuệ coi như bia ngắm sống.'],
                    'Bạch Mã Nghĩa Tòng': ['Khinh kỵ binh xung phong đâm sầm vào trận khiên kiên cố, cường nỗ như châu chấu bay, trảm mã kiếm đang bổ về phía đầu ngươi.'],
                    'Hãm Trận Doanh': ['Thành vỡ cự tuyệt đầu hàng, quân địch dùng xe khiên hạng nặng ép các ngươi vào vò thành chật hẹp, trường mâu điên cuồng đâm chém.'],
                    'Phi Hùng quân sĩ': ['Chủ công tử vong thiên hạ cùng thảo phạt, chi đội trọng kỵ tinh nhuệ nhất này của các ngươi trở thành mục tiêu tiêu diệt hàng đầu của các lộ chư hầu.'],
                    'Tịnh Châu Lang Kỵ': ['Chủ tướng binh bại bị bắt, các ngươi chạy tán loạn trên đồng bằng, bị cung nỗ thủ trọng trang của quân địch bắn chết hàng loạt.'],
                    'Liêu Đông thiết kỵ': ['Mưa bão liên miên đất bằng ngập nước chiến mã chết bệnh hàng loạt, trong vũng bùn trở thành bia ngắm sống cho bộ binh quân địch.'],
                    'Tây Lương thiết kỵ': ['Băng thiên tuyết địa lạc đường cạn lương, ban đêm đồng liêu vì tranh giành áo da chống rét mà rút đao chém giết lẫn nhau.'],
                    'U Châu đột kỵ': ['Cô lập không viện binh bị vây mấy tháng cạn lương, chủ tướng đã hạ lệnh giết hại nữ quyến đi theo quân để làm quân lương.'],
                    'Khương Hồ nghĩa tòng': ['Quân phiệt người Hán ăn bớt tiền thưởng, thủ lĩnh bộ lạc chuẩn bị làm phản trong đêm, ngươi không biết nên tạo phản hay là đi tố giác.'],
                    'Thanh Châu binh': ['Chủ soái vừa chết chuẩn bị làm phản về quê, lại bị trung quân tinh nhuệ bao vây trùng trùng điệp điệp, cuộc trấn áp đẫm máu sắp bắt đầu.'],
                    'Bạch Nhĩ Binh': ['Vì yểm trợ đại quân rút lui bị bỏ lại trên đồng bằng, gồng mình chống đỡ kỵ binh quân địch xung phong lặp đi lặp lại.'],
                    'Đông Châu binh': ['Bị thế lực bản địa cực kỳ thù hận, lương thảo cạn kiệt, xung quanh doanh trại toàn là tư binh địa phương tràn đầy địch ý.'],
                    'Kinh Châu nguyên tòng': ['Quanh năm chinh chiến bên ngoài tổn thất nặng nề, lại bị sĩ tộc bản địa âm thầm chèn ép ngáng chân, lương thảo phát xuống bị trộn đầy cát đất.'],
                    'Triều đình hàng thần': ['Bức bách bởi dâm uy mà đầu hàng, tân chủ cực kỳ nghi kỵ, một lần lỡ lời không quan trọng khiến ngươi bị tống vào ngục tối.'],
                    'Trọng Gia ngụy thần': ['Đi theo Viên Thuật xưng đế thất bại, ngươi trở thành kẻ phản nghịch bị thiên hạ cùng đánh, bách tính dọc đường ném đá vào ngươi.'],
                    'Phổ thông sĩ tốt': ['Bị sắp xếp vào đội ngũ tử sĩ đợt đầu tiên, lùi bước bị chém đầu, tiến lên bị nước sôi luộc thành đống thịt vụn.'],
                    'Trung quân bộ tốt': ['Bị trọng kỵ binh tập kích đội hình vuông chớp mắt bị xé toạc, móng sắt chiến mã đang giẫm về phía ngực ngươi.'],
                    'Tùy quân lão tốt': ['Trên đường đông chinh nhiễm bệnh thủy thổ không phục nghiêm trọng, bị vứt bỏ trong rừng sâu chờ chết, sói hoang đã lảng vảng gần đó.'],
                    'Man tộc cố dong binh': ['Tướng lĩnh người Hán ăn bớt tiền thưởng của các ngươi, sau khi Sa Ma Kha tử trận các ngươi bị quân Ngô săn lùng trong khu rừng xa lạ.'],
                    'Tây Lương bộ tốt': ['Không có kỵ binh yểm trợ, trên đồng bằng bị cường nỗ áp chế không ngóc đầu lên được, thương vong thảm trọng.'],
                    'Hà Bắc bộ tốt': ['Chủ tướng tử trận toàn quân tan rã, ngươi vì giành một miếng lương khô bị đồng liêu đâm thủng bụng.'],
                    'Hoài Nam bộ tốt': ['Chủ công tiếm quyền dẫn đến tứ diện thụ địch đại quân không có ý chí chiến đấu, vấp phải đợt xung phong đầu tiên liền tháo chạy toàn tuyến.'],
                    'Tấn quân sĩ tốt': ['Đóng quân ở vùng biên hoang hoặc theo quân viễn chinh gặp phải tình trạng nước non hiểm ác, khoang đáy chiến thuyền bị nước sông đổ đầy, cả con thuyền sắp chìm.'],
                    'Quan Lũng quận binh': ['Quanh năm chinh chiến mười nhà chín trống, kéo theo thân thể bệnh tật bị cưỡng ép trưng dụng còn phải tự mang theo lương khô nộp mạng.'],
                    'Bắc quân tướng sĩ': ['Trung ương quân bị cưỡng ép tháo dỡ thôn tính, kẻ phản kháng bị chém đầu trước công chúng, bị ép biên chế vào doanh trướng của kẻ thù.'],
                    'Nguyên tòng lão tốt': ['Thương bệnh quấn thân bị đại quân vứt bỏ nơi hoang dã, không lương không thuốc, sói hoang đang chằm chằm nhìn vào vết thương rỉ máu của ngươi.'],
                    'Nghĩa dũng hương binh': ['Lực lượng vũ trang tự phát bị quân chính quy coi là bia đỡ đạn, một đợt xung phong liền khiến bà con xóm làng thương vong quá nửa.'],
                    'Triều đình chính quy quân': ['Quân lương bị tham ô từng tầng, mặc áo giáp da rách nát đi trấn áp quân phản loạn trang bị tinh lương chẳng khác nào đi nộp mạng.'],
                    'Giang Đông thủy sư': ['Quân địch phóng hỏa đốt thuyền mặt sông hóa thành biển lửa, nhảy xuống sông bị chết đuối, ở lại thuyền bị thiêu thành than củi.'],
                    'Địa phương thủy quân': ['Trang bị cũ kỹ thiếu huấn luyện, đối mặt với sự va chạm của lâu thuyền chính quy, thuyền nhỏ vỡ vụn như giấy dán.'],
                    'Lâu thuyền thủy sư': ['Xuôi dòng mà xuống vấp phải hỏa thuyền tử sĩ đâm sầm vào, vật dẫn lửa đốt cháy vị trí chiến đấu không chỗ trốn.'],
                    'Trường Giang thủy doanh': ['Nước sông dâng cao cuốn trôi doanh trại, hạm đội quân địch mò mẫm tập kích trong đêm, còn đang trong giấc mộng đã bị chém đầu.'],
                    'Cẩm Phàm tặc': ['Cướp bóc thuyền lớn chở quân lương trúng kế, mặt sông xung quanh nổi lên bè lửa, phong tỏa thuyền nhẹ giữa lòng sông.'],
                    'Đồn điền khách': ['Hạn hán mất mùa, không nộp đủ quân lương sẽ bị chém đầu, vợ con sẽ bị sung vào quân doanh làm doanh kỹ.'],
                    'Đồn điền thanh tráng': ['Ngay cả áo giáp da cũng không có bị cưỡng ép gác đêm, máy bắn đá ném xuống tảng đá khổng lồ đập đồng hương thành đống thịt vụn.'],
                    'Lưu dân': ['Chạy nạn ba tháng gặm sạch vỏ cây, cửa ải phía trước bắn giết lưu dân phòng ôn dịch, truy binh phía sau trường mâu đã tới.'],
                    'Vô tịch lưu dân': ['Không có hộ tịch không thể vào thành, địa phương hào cường thả chó bắt các ngươi như dã thú đến mỏ quặng làm khổ sai.'],
                    'Quan Hệ': ['Đời đời tòng quân không được thoát tịch, phụ huynh đều chiến tử sa trường, ngươi chưa kịp nhược quán lại bị cưỡng chế đưa ra tiền tuyến.'],
                    'Bạch Đinh': ['Quân đội cưỡng ép bắt tráng đinh, ngươi bị xích sắt khóa lại trắng đêm lên đường, tụt hậu sẽ bị đốc chiến đội chặt đầu.'],
                    'Bố y': ['Loạn quân vào thành cướp bóc, ngươi bị coi như bia thịt kẹp ở giữa hai phe tranh đoạt, đao kiếm vô nhãn.'],
                    'Bình Dân': ['Quan phủ cưỡng ép phân bổ thuế má, ngươi bán nhi dục nữ vẫn gom không đủ số, nha dịch đang chuẩn bị dỡ xà nhà của ngươi.'],
                    'Tứ thế tam công': ['Chính địch dâng lên quân phiệt nắm quyền thư từ mưu phản giả mạo, ngoài thành ba ngàn giáp sĩ đã phong tỏa triệt để trang viên nhà ngươi.'],
                    'Thanh lưu danh sĩ': ['Ngươi vì cự tuyệt tiếp nhận quyền thần trưng bích và viết văn thống mạ xuất thân của hắn, thích khách của Hiệu Sự Phủ đã lẻn vào nơi ẩn náu của ngươi.'],
                    'Địa phương danh sĩ': ['Thứ sử mới tới bản địa vì để lập uy, cưỡng ép thêu dệt tội danh tống ngươi vào ngục, đình úy đang chuẩn bị dùng trọng hình với ngươi.'],
                    'Hàn môn thứ tộc': ['Ngươi vất vả lắm mới dựa vào quân công mưu được một quan bán chức, lại bị thế gia tử đệ liên danh hặc tội, sắp bị tước đoạt quan chức phát phối sung quân.'],
                    'Bản thổ vọng tộc': ['Quân phiệt bên ngoài cưỡng ép thanh tra ruộng đất hộ khẩu ẩn nấp, binh khí nhà ngươi cất giấu bị lục soát ra, họa diệt môn gần ngay trước mắt.'],
                    'Địa phương hào cường': ['Chiến loạn liên miên dẫn đến quân phiệt lương thảo khô kiệt, bọn họ đánh cờ hiệu "mượn lương", thực chất chuẩn bị dẫn binh huyết tẩy ổ bảo của ngươi.'],
                    'Tông tộc trưởng giả': ['Tử đệ trẻ tuổi trong tộc va chạm gia quyến quân phiệt đi ngang qua, chủ tướng đối phương bạo nộ, yêu cầu giao ra toàn tộc thanh tráng sung làm tiền tuyến tử sĩ.'],
                    'Thế gia tử đệ': ['Gia tộc trong đấu tranh chính trị tàn khốc đứng sai đội bị nhổ tận gốc, ngươi mang theo ngọc tỷ cùng tín vật đang trong bùn lầy trốn tránh truy sát.'],
                    'Ổ bảo bảo chủ': ['Bốn phía bị Hoàng Cân loạn quân đói đỏ mắt trùng trùng bao vây, giếng nước trong ổ bảo khô cạn, gia đinh đã bắt đầu xì xào bàn tán chuẩn bị hiến thủ cấp của ngươi cầu sinh.']
                }
            }
        };

        function getClassCrises(year, faction, className) {
            const mode = userData.mode;
            let crises = [];

            let classCrises = [];
            if (mode === 'Chính Sử' && crisisData.classSpecific['Chính Sử']) {
                for (let key in crisisData.classSpecific['Chính Sử']) {
                    if (className.includes(key)) {
                        classCrises = classCrises.concat(crisisData.classSpecific['Chính Sử'][key]);
                        break;
                    }
                }
            }

            let factionCrises = [];
            const modeData = crisisData.specific[mode];
            if (modeData && modeData[year]) {
                for (let key in modeData[year]) {
                    if (faction.includes(key) || key.includes(faction) ||
                        (faction.includes('Lưu Bị') && key.includes('Thục')) ||
                        (faction.includes('Tào') && key.includes('Ngụy')) ||
                        (faction.includes('Tôn') && key.includes('Ngô'))) {
                        factionCrises = factionCrises.concat(modeData[year][key]);
                    }
                }
            }

            const isLow = isLowClass(className);
            if (!isLow) {
                factionCrises = factionCrises.filter(c =>
                    !c.includes('Vệ sĩ') && !c.includes('Sĩ tốt') && !c.includes('Binh') && !c.includes('Tiểu tốt') && !c.includes('Thôi trước')
                );
            }

            crises = classCrises.concat(factionCrises);

            if (crises.length === 0) {
                if (mode === 'Chính Sử') {
                    if (className.includes('Lưu dân') || className.includes('Bình dân') || className.includes('Bố y') || className.includes('Bạch đinh') || className.includes('Hàn môn')) {
                        crises.push('Trong thôn đại hạn xuất hiện đổi con mà ăn, đội giục lương của đốc nông quan đang đi từng nhà vơ vét hạt túc mễ cuối cùng.');
                    } else if (className.includes('Thủ lĩnh') || className.includes('Chủ soái') || className.includes('Minh chủ') || className.includes('Đô đốc') || className.includes('Quân') || className.includes('Quân phiệt')) {
                        crises.push('Hai gã hạch tâm thống binh đại tướng vì đoạt binh quyền âm thầm hạ độc lẫn nhau, cường địch đại quân đang hướng biên cảnh tập kết.');
                    } else if (className.includes('Thần') || className.includes('Danh sĩ') || className.includes('Thế tộc') || className.includes('Đại tộc') || className.includes('Công khanh') || className.includes('Tông thân')) {
                        crises.push('Chính địch giả mạo thư từ các ngươi thông địch mưu phản, giáp sĩ của Đình Úy Phủ đã bao vây phủ đệ của ngươi.');
                    } else if (className.includes('Hoạn quan') || className.includes('Ngoại thích') || className.includes('Thường thị') || className.includes('Hoàng môn')) {
                        crises.push('Triều đình chính biến, mật chiếu thanh tẩy loạn đảng hạ đạt, cửu môn phong tỏa ngươi ngay cả cơ hội ra khỏi thành chạy trốn cũng không có.');
                    } else if (className.includes('Tốt') || className.includes('Quân') || className.includes('Kỵ') || className.includes('Tướng') || className.includes('Binh')) {
                        crises.push('Trong doanh bộc phát thương hàn nghiêm trọng, ngươi phụ trách chôn cất đồng bào, phát hiện trong đó còn có người sống bị ném vào hố.');
                    } else {
                        crises.push('Ngươi phát hiện thượng quan nhận hối lộ của địch quốc, hắn âm thầm khấu trừ vật tư bảo mệnh của ngươi chuẩn bị để ngươi chết ở hoang dã.');
                    }
                } else {
                    crises.push('Ngươi đối mặt quần hùng vây quanh, đại quân lương thảo sắp cạn kiệt, nội bộ nhân tâm tư biến.');
                }
            }

            crises = [...new Set(crises)].slice(0, 4);
            return crises.map(c => ({
                name: c,
                desc: ''
            }));
        }

