        function displaySummary() {
            const summaryInfo = document.getElementById('summary-info');
            let html = `
        <div class="edit-icon" onclick="openEditModal('normal')" title="Sửa đổi thiết lập">✎ Sửa đổi</div>
        <strong> Tuyến đường vui chơi:</strong> ${userData.route || 'Chưa Rõ'}<br>
