                    },
                    "Tiêu Đề": userData.situation.title || "",
                    "Hướng Kịch Bản": userData.mode || "Không",
                    "Đại Thế Thời Đại": "Thiên Hạ Đại Thế, Phân Cửu Tất Hợp, Hợp Cửu Tất Phân.",
                    "Khủng Hoảng Hiện Tại": userData.crisis || "Tạm Không Có",
                    "Thiên Tượng": "Tinh Tượng Bình Chính",
                    "Đồng Dao": "Tạm Không Có"
                },
                "Trạng Thái Nhân Vật Chính": {
                    "Họ Tên": displayName || "Chờ Thiết Lập",
                    "Biểu Tự": userData.zi || "Không",
                    "Tuổi Tác": parseInt(userData.age) || 20,
                    "Quan Chức": userData.position || "Không",
                    "Phe Phái": factionName,
                    "Giai Cấp Xuất Thân": userData.classLevel || "Bình Dân",
                    "Khu Vực Hiện Tại": userData.customRegion || "Chưa Rõ",
                    "Danh Tiếng": {
                        "Tiêu Đề": userData.reputation || "Lý Lư Xưng Thiện",
                        "Mô Tả": ""
                    },
                    "Thuộc Tính": attr,
                    "Bẩm Phú": {},
                    "Công Tích": {},
                    "Danh Hiệu": {},
                    "Tin Đồn Mỹ Nhân Thiên Hạ": "Tạm Không Có",
                    "Đánh Giá Giai Cấp": "Bình Bình Vô Kỳ"
                },
                "Hệ Thống Kinh Tế": {
                    "Dự Trữ_Vàng": userData.assets?.gold || 0,
                    "Dự Trữ_Thạch": userData.assets?.food || 0,
                    "Dự Trữ_Tiền": 0,
                    "Dự Trữ_Thất": 0,
                    "Chi Tiết Tài Sản": {}
                },
                "Quan Hệ Thế Lực": {
