                        "Động Thái Phe Phái": userData.faction_dynamic || "Án Binh Bất Động",
                        "Đánh Giá Phe Mình": "Trung Lập",
                        "Đánh Giá Phe Bên Ngoài": {}
                    },
                    "Quan Hệ Nhân Tế": {},
                    "Thuộc Hạ": {}
                },
                "Hệ Thống Quân Sự": {
                    "Binh Mã": {}
                },
                "Hệ Thống Gia Tộc": {
                    "Khái Quát": {
