                    "Động Hướng Tử Tự": "Trưởng Thành Khỏe Mạnh",
                    "Tử Tự": {}
                }
            };

            // Nạp Bẩm phú người chơi
            if (userData.selectedTraits && userData.selectedTraits.length > 0) {
                userData.selectedTraits.forEach(t => {
                    schemaData["Trạng Thái Nhân Vật Chính"]["Bẩm Phú"][t.name] = {
                        "Gia Thành": t.effects,
                        "Mô Tả": ""
                    };
                });
            }
            if (userData.customTrait) {
                schemaData["Trạng Thái Nhân Vật Chính"]["Bẩm Phú"]["Đặc thù"] = {
                    "Gia Thành": userData.customTrait,
                    "Mô Tả": "Bẩm phú tự thiết lập"
                };
            }

            // Nạp Kinh tế
            if (userData.assets && userData.assets.name !== 'Không Có') {
                schemaData["Hệ Thống Kinh Tế"]["Chi Tiết Tài Sản"][userData.assets.name] = {
                    "Thu Nhập": userData.assets.income || 0,
                    "Chi Tiêu": userData.assets.expense || 0,
                    "Loại Hình": "Vàng"
                };
            }

            // Nạp Quân Sự và Hạch tâm thuộc hạ
            if (userData.force && userData.force.power) {
                let pwrNum = parseInt(userData.force.power.replace(/\D/g, ''));
                if (isNaN(pwrNum) || pwrNum === 0) pwrNum = 5000;
                schemaData["Hệ Thống Quân Sự"]["Binh Mã"]["Bộ đội trực thuộc"] = {
                    "Số Lượng": pwrNum,
                    "Trú Địa": userData.customRegion || "Chưa Rõ",
                    "Chủ Tướng": displayName || "Không",
                    "Tình Trạng Trung Thành": "Bình Thường",
                    "Trạng Thái Tiếp Tế": "Đầy Đủ",
                    "Sĩ Khí": "Cao Ngang",
                    "Huấn Luyện": "Hữu Tố",
                    "Trang Bị": "Tinh Lương",
                    "Động Thái Binh Mã": "Đồn Trú",
                    "Giải Thích": "Tạm Không Có"
                };

                if (userData.force.subordinates) {
                    const subs = userData.force.subordinates.split(/[.,，、]/);
                    subs.forEach(s => {
                        let subName = s.trim();
                        if (subName) {
                            schemaData["Quan Hệ Thế Lực"]["Thuộc Hạ"][subName] = {
                                "Quan Chức": "Bộ tướng",
                                "Hảo Cảm": 80,
                                "Đánh Giá": "Trung Thành"
                            };
                        }
                    });
                }
            }

            // Nạp Thuộc hạ tự thiết lập (Tâm phúc)
            if (userData.customSubordinate && userData.customSubordinate.name) {
                schemaData["Quan Hệ Thế Lực"]["Thuộc Hạ"][userData.customSubordinate.name] = {
                    "Tuổi Tác": parseInt(userData.customSubordinate.age) || 20,
                    "Quan Chức": "Tâm phúc",
                    "Hảo Cảm": 100,
                    "Đánh Giá": userData.customSubordinate.customInfo || "Trung Tâm Cảnh Cảnh",
                    "Thuộc Tính": userData.customSubordinate.attributes || {
                        "Dũng Vũ": 60,
                        "Thao Lược": 60,
                        "Nội Chính": 60,
                        "Thống Ngự": 60,
                        "Khí Độ": 60,
                        "Sức Khỏe": 100
                    }
                };
            }

            // Nạp Quan hệ nhân tế
            if (userData.relations) {
                schemaData["Quan Hệ Thế Lực"]["Quan Hệ Nhân Tế"]["Ghi chú"] = {
                    "Hảo Cảm": 0,
                    "Đánh Giá": userData.relations
                };
            }

            // Nạp Thiết lập khác vào phần Danh hiệu (hoặc Mô tả chung)
            if (userData.custom) {
                schemaData["Trạng Thái Nhân Vật Chính"]["Danh Hiệu"]["Thiết lập phụ"] = userData.custom;
            }

            // Trả về JSON bọc trong Markdown Code Block để AI tự động parse
            return "```json\n" + JSON.stringify(schemaData, null, 4) + "\n```";
        }

