        function setupHistPage() {
            var histModeContainer = document.getElementById('hist-mode-cards');
            histModeContainer.innerHTML = '';
            var modes = [{
                name: 'Chính Sử',
                desc: 'Nghiêm ngặt sử thực'
            }, {
                name: 'Diễn Nghĩa',
                desc: 'Truyền kỳ lãng mạn'
            }];
            modes.forEach(function(m) {
                var card = document.createElement('div');
                card.className = 'sub-card';
                if (m.name === userData.mode) card.classList.add('selected');
                card.innerHTML = '<div class="card-title">' + m.name + '</div><div class="card-desc">' + m.desc + '</div>';
                card.onclick = function() {
                    selectCard(card, 'hist-mode-cards');
                    userData.mode = m.name;
                };
                histModeContainer.appendChild(card);
            });

            var histDirContainer = document.getElementById('hist-direction-cards');
            histDirContainer.innerHTML = '';
            var dirs = [{
                name: 'Lấy người chơi làm cốt lõi',
                desc: 'Cho phép viết lại lịch sử'
            }, {
                name: 'Người chơi làm bối cảnh',
                desc: 'Tuân theo quỹ đạo đã định'
            }];
            dirs.forEach(function(d) {
                var card = document.createElement('div');
                card.className = 'sub-card';
                if (d.name === userData.scriptDirection) card.classList.add('selected');
                card.innerHTML = '<div class="card-title">' + d.name + '</div><div class="card-desc">' + d.desc + '</div>';
                card.onclick = function() {
                    selectCard(card, 'hist-direction-cards');
                    userData.scriptDirection = d.name;
                };
                histDirContainer.appendChild(card);
            });

            var attrContainer = document.getElementById('hist-attr-area');
            attrContainer.innerHTML = '';
            attributesList.forEach(function(attr) {
                var group = document.createElement('div');
                group.className = 'attr-slider-group';
                var header = document.createElement('div');
                header.className = 'attr-header';
                header.innerHTML = '<div class="attr-name">' + attr + '</div>';
                var numberInput = document.createElement('input');
                numberInput.className = 'attr-number-input';
                numberInput.type = 'number';
                numberInput.min = '-100';
                numberInput.max = '100';
                numberInput.value = '0';
                numberInput.id = 'hist-attr-num-' + attr;
                header.appendChild(numberInput);
                var slider = document.createElement('input');
                slider.className = 'attr-slider';
                slider.type = 'range';
                slider.min = '-100';
                slider.max = '100';
                slider.value = '0';
                slider.step = '1';
                slider.id = 'hist-attr-slider-' + attr;
                var updateUI = function(val) {
                    var num = parseInt(val, 10);
                    if (isNaN(num)) num = 0;
                    if (num > 100) num = 100;
                    if (num < -100) num = -100;
                    slider.value = num;
                    numberInput.value = num;
                };
                slider.addEventListener('input', function(e) {
                    updateUI(e.target.value);
                });
                numberInput.addEventListener('input', function(e) {
                    updateUI(e.target.value);
                });
                numberInput.addEventListener('blur', function(e) {
                    if (e.target.value === '') updateUI(0);
                });
                group.appendChild(header);
                group.appendChild(slider);
                attrContainer.appendChild(group);
            });
        }

        function collectHistData() {
            var name = document.getElementById('hist-name').value.trim();
            if (!name) {
                alert('Vui lòng nhập họ tên');
                return null;
            }
            var crisis = document.getElementById('hist-crisis').value.trim();
            if (!crisis) {
                alert('Vui lòng điền khủng hoảng hiện tại');
                return null;
            }
            var modeSelected = document.querySelector('#hist-mode-cards .sub-card.selected');
            if (modeSelected) userData.mode = modeSelected.querySelector('.card-title').innerText;
            if (!userData.mode || (userData.mode !== 'Chính Sử' && userData.mode !== 'Diễn Nghĩa')) {
                alert('Vui lòng chọn hướng kịch bản');
                return null;
            }
            var dirSelected = document.querySelector('#hist-direction-cards .sub-card.selected');
            if (dirSelected) userData.scriptDirection = dirSelected.querySelector('.card-title').innerText;
            if (!userData.scriptDirection) {
                alert('Vui lòng chọn chế độ tự sự');
                return null;
            }

            userData.route = 'Đóng Vai Nhân Vật Lịch Sử';
            userData.name = name;
            userData.zi = document.getElementById('hist-zi').value.trim();
            userData.age = document.getElementById('hist-age').value.trim();
            var year = parseInt(document.getElementById('hist-year').value) || 200;
            var eraTitle = document.getElementById('hist-era-title').value.trim() || 'Chưa định';
            var eraDesc = document.getElementById('hist-era-desc').value.trim() || '';
            userData.situation = {
                year: year,
                title: eraTitle,
                desc: eraDesc,
                factions: []
            };
            var faction = document.getElementById('hist-faction').value.trim() || 'Chưa định';
            userData.faction = faction;
            userData.customFactionName = faction;
            userData.classLevel = document.getElementById('hist-class').value.trim() || 'Chưa định';
            userData.position = document.getElementById('hist-position').value.trim() || '';
            userData.region = 'Tùy Chỉnh Khu Vực';
            userData.customRegion = document.getElementById('hist-region').value.trim() || 'Chưa định';
            var forcePower = document.getElementById('hist-force-power').value.trim();
            var forceSub = document.getElementById('hist-force-sub').value.trim();
            if (forcePower || forceSub) {
                userData.force = {
                    name: faction,
                    power: forcePower,
                    subordinates: forceSub
                };
            } else {
                userData.force = {
                    name: '',
                    power: '',
                    subordinates: ''
                };
            }
            userData.reputation = document.getElementById('hist-reputation').value;
            userData.attributes = {};
            attributesList.forEach(function(attr) {
                userData.attributes[attr] = parseInt(document.getElementById('hist-attr-num-' + attr).value) || 0;
            });
            var traitsText = document.getElementById('hist-traits').value.trim();
            userData.selectedTraits = [];
            if (traitsText) {
                traitsText.split('\n').forEach(function(line) {
                    var trimmed = line.trim();
                    if (!trimmed) return;
                    var nameMatch = trimmed.match(/^([^((]+)/);
                    var effectMatch = trimmed.match(/[((]([^))]+)[))]/);
                    userData.selectedTraits.push({
                        name: nameMatch ? nameMatch[1].trim() : trimmed,
                        effects: effectMatch ? effectMatch[1].trim() : ''
                    });
                });
            }
            userData.customTrait = '';
            userData.assets = {
                name: document.getElementById('hist-asset-name').value.trim() || 'Không Có',
                income: parseInt(document.getElementById('hist-asset-income').value) || 0,
                expense: parseInt(document.getElementById('hist-asset-expense').value) || 0,
                food: parseInt(document.getElementById('hist-asset-food').value) || 0,
                gold: parseInt(document.getElementById('hist-asset-gold').value) || 0
            };
            userData.crisis = crisis;
            userData.family_info = document.getElementById('hist-family').value.trim();
            userData.relations = document.getElementById('hist-relations').value.trim();
            userData.faction_dynamic = document.getElementById('hist-faction-dynamic').value.trim();
            userData.custom = document.getElementById('hist-custom').value.trim();
            return userData;
        }

        function showHistPreview() {
            var data = collectHistData();
            if (!data) return;
            var modal = document.getElementById('preview-modal');
            var textarea = document.getElementById('preview-textarea');
            var copyBtn = document.getElementById('btn-copy');
            textarea.value = formatUserDataAsMessage();
            copyBtn.innerText = 'Sao chép thông tin';
            copyBtn.style.borderColor = 'var(--theme-main)';
            copyBtn.style.color = 'var(--theme-main)';
            modal.classList.add('show');
        }

        function onHistConfirm() {
            var data = collectHistData();
            if (!data) return;
            try {
                var charWB = getCharWorldbookNames('current');
                var wbName = charWB.primary;
                if (!wbName) {
                    alert('Thẻ nhân vật hiện tại chưa liên kết thế giới thư chính.');
                    return;
                }
                deleteWorldbookEntries(wbName, function(entry) {
                    return entry.name === 'Thông Tin Người Dùng';
                }).then(function() {
                    return createWorldbookEntries(wbName, [{
                        name: 'Thông Tin Người Dùng',
                        enabled: true,
                        strategy: {
                            type: 'constant'
                        },
                        position: {
                            type: 'before_character_definition'
                        },
                        content: formatUserDataAsContent()
                    }]);
                }).then(function() {
                    return createChatMessages([{
                        role: 'user',
                        message: formatUserDataAsMessage()
                    }]);
                }).then(function() {
                    return triggerSlash('/trigger');
                }).catch(function(err) {
                    alert('Thao tác thất bại: ' + (err.message || String(err)));
                });
            } catch (e) {
                console.log('Final Hist Data:', formatUserDataAsMessage());
                alert('APIGọi thất bại: ' + e.message);
            }
        }

        document.addEventListener('DOMContentLoaded', () => {
            document.getElementById('start-button').addEventListener('click', () => goToPage('1'));
            setupOriginPage();
            updateStepIndicator();
        });
    </script>
